MultiLanguageSpellData['fr'][465999] = {name = "Grogneur cuirassé cramoisi", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie cette monture.\n[q]\"Il y en a parmi les Gobelins et les Gobelines qui appellent affectueusement les hyènes apprivoisées des « Grogneurs ». Celle-ci adore creuser.\"\nVendeur :\nRocco Razzboum\nRégion :\nTerremine\nCoût :\n8 125"}
MultiLanguageSpellData['fr'][466000] = {name = "Gueule broyeuse imprégnée de ténèbres", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie cette monture.\n[q]\"Considérée comme une cheffe de meute des hyènes de la casse de Stix Jettetout, elle mord assez fort pour broyer tout ce que Gallywix veut éliminer, qu’il s’agisse d’objets ou de personnes…\"\nVendeur :\nAndo le Gat\nZone :\nLibération de Terremine\nCoût :\n500"}
MultiLanguageSpellData['fr'][466001] = {name = "Frappeur des Flots noirs", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie cette monture.\n[q]\"Faites attention à vos os si vous ne voulez pas qu’on les écrase.\"\nButin :\ntrésor des Flots noirs\nRégion :\nTerremine"}
MultiLanguageSpellData['fr'][466002] = {name = "Grogneur cuirassé violet", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie cette monture.\n[q]\"Smaks connaît deux ou trois trucs pour s’occuper des hyènes. Règle numéro 1 : gardez vos mains à bonne distance de leurs crocs !\"\nVendeur :\nSmaks Rasesurface\nRégion :\nTerremine\nCoût :\n8 125"}
