MultiLanguageSpellData['fr'][466011] = {name = "Fusendo le Furieux", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie cette monture.\n[q]\"Être VIP parmi les VIP du Gallagio, ça a ses avantages, comme avoir les clés de cet ancien roi du carnage. La technologie gobeline de pointe lui permet de parcourir plus de 100 mètres par litre !\""}
MultiLanguageSpellData['fr'][466012] = {name = "Tir accidentel de baril du tonnerre", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie cette monture.\n[q]\"Une fusée récupérée dans les gradins du Chaudron après un affrontement particulièrement brutal. Lorsqu’on lui a demandé si elle était désamorcée, l’opérateur de Torq a simplement répondu : « Sans doute ? »\"\nVendeur :\nAndo le Gat\nZone :\nLibération de Terremine\nCoût :\n500"}
