MultiLanguageSpellData['fr'][467021] = {name = "Frénésie de griffes", additional_info = "Allonge\n1 s d'incantation\n[q]Le lanceur ou la lanceuse entre dans une colère noire et inflige des dégâts physiques à la cible adverse toutes les 0.5 s pendant 3.4 s."}
MultiLanguageSpellData['fr'][467024] = {name = "Transport de Kaja’Cola", additional_info = "[q]Les curiosités fourvoyées ont désormais 35 % de chances de contenir 1 unité de Kaja’Cola et Brann fait maintenant apparaître une fois par Gouffre un pack de 6 à la création des feux de camp.\n\n Plusieurs parfums de Kaja’Cola existent, chacun appliquant un effet spécifique une fois collecté."}
MultiLanguageSpellData['fr'][467026] = {name = "Grenade goblomagnétique rebondissante", additional_info = "[q]En combat, Brann a une chance de lancer une grenade GGR sur la cible adverse, laquelle subit alors des dégâts de nature modérés et a 20 % de chances d’être étourdie pendant 1.5 s. La grenade a 25 % de chances de rebondir sur une nouvelle cible.\n\n Elle peut également rebondir sur les membres du groupe sans leur infliger des dégâts ou les étourdir."}
MultiLanguageSpellData['fr'][467029] = {name = "Matrice de conversion d’impact", additional_info = "[q]En entrant en combat, Brann active la matrice de conversion pendant 10 s. Tant que l’effet est actif, un faible pourcentage de tous les dégâts infligés par le groupe est converti en caractéristique principale et réparti entre les membres du groupe.\n\n Lorsque la matrice de conversion s’éteint, le bonus à la caractéristique principale persiste pendant 10 s. Cet effet ne peut se produire plus d’une fois toutes les 2 min."}
MultiLanguageSpellData['fr'][467031] = {name = "Flux de Sang noir", additional_info = "Portée illimitée\nInstantanée\n[q]Du Sang noir se déverse du plafond de l’usine, infligeant 14 point de dégâts d’ombre toutes les 0.5 s."}
MultiLanguageSpellData['fr'][467032] = {name = "Feu d’œuf", additional_info = nil}
MultiLanguageSpellData['fr'][467033] = {name = "RAID-R @ 8UT1N", additional_info = "[q]Toutes les 60 s ou 5 s après l’entrée en combat, analyse l’environnement pour signaler les curiosités fourvoyées et augmenter de 4 % les dégâts que subissent les adversaires disposant de moins de 95 % de points de vie pendant 10 s."}
MultiLanguageSpellData['fr'][467034] = {name = "Bombe mortelle gobeline à technologie inversée", additional_info = "[q]En combat, lorsque les points de vie d’un personnage-joueur tombent sous 50 %, Brann lance une bombe géante qui explose à l’impact.\n\n L’explosion repousse et ralentit de 45 % les adversaires alentour pendant 5 s. En outre, elle rend 35 % de leur maximum de points de vie aux membres du groupe proches. Cet effet ne peut se produire qu’une fois toutes les 1.5 min."}
MultiLanguageSpellData['fr'][467035] = {name = "Aimant beaucoup trop grand", additional_info = "[q]Lorsque Brann lance Outils de collecte , il a 100 % de chances de magnétiser des plaques métalliques abandonnées sur des membres du groupe, ce qui leur octroie un bouclier à hauteur de 5 % de leur maximum de points de vie qui se régénère hors combat.\n\n Outils de collecte\nBrann utilise ses outils de collecte pour aider les personnages-joueurs à trouver de l’or, du minerai, des plantes, des poissons, du cuir et des trésors supplémentaires."}
MultiLanguageSpellData['fr'][467036] = {name = "Dispositif de fusées bioalimenté", additional_info = "[q]Les membres du groupe sont équipés |2 Dispositif de fusées bioalimenté .\n\n Biocarburant\n Chaque personnage adverse tué alimente le Dispositif de fusées bioalimenté , ce qui augmente la vitesse de déplacement de 2 % et la Hâte de 2 % pendant 10 s. Cumulable jusqu’à 10 fois."}
MultiLanguageSpellData['fr'][467037] = {name = "Puce d’augmentation pistée", additional_info = "[q]Le maximum de points de vie de Brann augmente de 4 % et ses dégâts et soins de 20 %.\n\n En combat, des robots mécaniques pouvant être détruits ou dissipés ciblent parfois Brann et le traquent. Lorsqu’ils l’atteignent, Brann subit des dégâts à hauteur de 30 % de son maximum de points de vie et est étourdi pendant 5 s."}
