MultiLanguageSpellData['fr'][470053] = {name = "Brasier voltaïque", additional_info = "Approximativement 5.75 activations par minute\n[q]Éclair et Chaîne d’éclairs ont une chance élevée de transformer votre prochain Horion de flamme en Brasier voltaïque.\n\nBrasier voltaïque\nFoudroie instantanément la cible et 5 adversaires proches avec un tonnerre incandescent, infligeant ([400% of Spell Power]) points de dégâts de nature et appliquant Horion de flamme.\n\n Génère 1 charges d’Arme du Maelström.\n(1sec de recharge)"}
