MultiLanguageSpellData['fr'][470055] = {name = "T.R.I.S.T.E.", additional_info = "Instantanée\n[q]Ajoute une châsse à un objet de la saison 2 de The War Within qui en est dépourvu. Peut être utilisé sur les heaumes, brassards ou ceintures. Ne peut pas être utilisé sur de l’équipement JcJ."}
