MultiLanguageSpellData['fr'][470168] = {name = "Zéphyr de Cyrcé", additional_info = "Instantanée\n[q]Lorsque vous vous trouvez sur l’île aux Sirènes en ayant équipé le diadème de Cyrcé, vos sorts et techniques ont une chance d’invoquer le zéphyr de Cyrcé, qui lance toutes les techniques de citrine chantante existantes en 3 s."}
MultiLanguageSpellData['fr'][470169] = {name = "Larrons des sirènes", additional_info = "Instantanée\n[q]Le diadème de Cyrcé vous permet de manière passive d’illuminer les adversaires invisibles qui essaient de dérober des trésors sur l’île aux Sirènes. On les trouve notamment à essayer de voler le fer béni par la flamme des créatures les plus puissantes de l’île."}
