MultiLanguageSpellData['fr'][470197] = {name = "Bénédiction marinicole", additional_info = "Instantanée\n[q]Permet de manière passive de marcher sur le fond marin, de trouver des trésors sous-marins, de respirer sous l’eau et de nager beaucoup plus vite lorsque vous vous trouvez dans les eaux entourant l’île aux Sirènes.\n\n Le diadème de Cyrcé doit être équipé."}
