MultiLanguageSpellData['fr'][470593] = {name = "Infliger la mort", additional_info = "30 m de portée\n{3 s d'incantation} {3 s de recharge}\n[q]Le lanceur ou la lanceuse canalise la mort sur la cible, lui inflige des dégâts d’ombre toutes les 1 s pendant 5 s et réduit sa vitesse de déplacement de 50 %."}
MultiLanguageSpellData['fr'][470596] = {name = "Détonation de givrefeu", additional_info = "100 m de portée\nInstantanée\n[q]Feu\nLe lancement de Météore fait que votre prochain Trait de feu explose en une Détonation de givrefeu, infligeant ([265.6% of Spell Power]) point de dégâts de givrefeu aux adversaires proches. Dégâts réduits au-delà de 8 cibles.\n\n Détonation de givrefeu réduit le temps de recharge de Flammes de phénix de 5 s.\n\nGivre\nLe lancement de Tempête de comètes fait que votre prochain Javelot de glace explose en une Détonation de givrefeu, infligeant ([265.6% of Spell Power]) point de dégâts de givrefeu aux adversaires proches. Dégâts réduits au-delà de 8 cibles.\n\n Détonation de givrefeu a 50 % de chances de conférer Gel mental."}
MultiLanguageSpellData['fr'][470598] = {name = "Implorer le seigneur du Feu", additional_info = "Instantanée\n[q]Lorsque Dagran descend en dessous de 70 % de points de vie, il implore l’aide du seigneur du Feu, ce qui lui confère un bouclier qui absorbe 38722016 point de dégâts.\n\n Un avatar de Ragnaros rejoint la bataille et inflige 3872202 point de dégâts de feu à tous les personnages-joueurs. Les dégâts sont réduits à mesure que l’on s’éloigne du point d’impact."}
MultiLanguageSpellData['fr'][470599] = {name = "Mot de l’ombre : Nécrose", additional_info = "{1 s d'incantation} {5 min de recharge}\n[q]Inflige à un personnage-joueur une contagion ténébreuse réduisant les soins reçus de 90 %. Le fait de se tenir à moins de 5 m d’un autre personnage-joueur pendant 1 s transmet celle-ci au personnage-joueur proche et déclenche Détonation nécrotique ."}
MultiLanguageSpellData['fr'][470600] = {name = "Mot de l’ombre : Nécrose", additional_info = "200 m de portée\nInstantanée\n[q]Inflige à un personnage-joueur une contagion ténébreuse réduisant les soins reçus de 90 %. Le fait de se tenir à moins de 5 m d’un autre personnage-joueur pendant 1 s transmet celle-ci au personnage-joueur proche et déclenche Détonation nécrotique ."}
