MultiLanguageSpellData['fr'][470602] = {name = "Détonation nécrotique", additional_info = "Instantanée\n[q]Inflige 585 point de dégâts d’ombre à tous les personnages-joueurs."}
MultiLanguageSpellData['fr'][470603] = {name = "Nécrose rémanente", additional_info = "200 m de portée\nInstantanée\n[q]Après avoir transmis Mot de l’ombre : Nécrose, le personnage-joueur subit Nécrose rémanente ."}
