MultiLanguageSpellData['fr'][473715] = {name = "Sombre trait", additional_info = "30 m de portée\n2 s d'incantation\n[q]Le lanceur ou la lanceuse frappe la cible avec un trait qui inflige 2934781 point de dégâts d’ombre et absorbe 2501944 point de vie rendu pendant 15 s."}
MultiLanguageSpellData['fr'][473716] = {name = "Tour astucieux avec une corde", additional_info = "40 m de portée\nInstantanée\n[q]Lorsqu’un personnage adversaire attaque un joueur, Brann lance son fidèle lasso, attirant l’adversaire vers lui. Un même personnage adverse ne peut pas être attrapé au lasso plus d’une fois toutes les 10 s."}
MultiLanguageSpellData['fr'][473718] = {name = "Pistolet électrochargé", additional_info = "40 m de portée\nInstantanée\n[q]L’équipement de Brann est enrichi de nouvelles technologies de pointe.\n\nBouclier électrochargé\n Les soins effectifs prodigués à Brann se répercutent sous forme de dégâts de nature sur les adversaires proches.\n\nPistolet électrochargé\n Chaque tir provoque un courant électrique qui traverse les personnages adverses proches et réduit leur vitesse d’attaque. Les soins prodigués à Brann lui permettent de surcharger son pistolet afin d’infliger davantage de dégâts.\n\nFusil électrochargé\n Chaque personnage adverse touché a une chance d’être renversé. Les soins prodigués à Brann lui permettent de surcharger son fusil afin d’infliger davantage de dégâts."}
MultiLanguageSpellData['fr'][473719] = {name = "Gel explosif cinétique", additional_info = "Portée illimitée\nInstantanée\n[q]Keeza colle sur un personnage-joueur un gel explosif cinétique qui lui inflige 1818337 point de dégâts de feu toutes les 1 s pendant 12 s.\n\n La suppression de l’effet fait exploser le gel avec violence, infligeant 2424449 point de dégâts de feu aux personnages-joueurs et projetant dans les airs toutes les bombes à retardement toquantes à moins de 5 m."}
