MultiLanguageSpellData['fr'][473743] = {name = "Roulepatte meeksi", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie cette monture.\n[q]\"Les roulepattes sont très fiers de porter le thé. Ils sont toujours prêts à en offrir une tasse bien chaude à leurs compagnie de voyage.\"\nBoutique en jeu"}
