MultiLanguageSpellData['fr'][473895] = {name = "Reglobulification", additional_info = "Canalisée (12 s d'incantation)\n[q]Globikus réassimile sa forme, s’entourant d’un bouclier qui absorbe jusqu’à 14296823 point de dégâts et le soigne de 2 % de ses points de vie toutes les 2 s pendant jusqu’à annulation."}
MultiLanguageSpellData['fr'][473896] = {name = "Charge statique", additional_info = "Portée illimitée\nInstantanée\n[q]Charge un personnage adverse d’énergie et lui inflige 0 point de dégâts de nature toutes les 1 s pendant 12 s. Tant que la cible est affectée, l’électricité statique inflige aussi périodiquement à ses alliés proches des dégâts de nature."}
