MultiLanguageSpellData['fr'][474572] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nTransport de Kaja’Cola\n[q]Les curiosités fourvoyées ont désormais 35 % de chances de contenir 1 unité de Kaja’Cola et Brann fait maintenant apparaître une fois par Gouffre un pack de 6 à la création des feux de camp.\n\n Plusieurs parfums de Kaja’Cola existent, chacun appliquant un effet spécifique une fois collecté.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][474573] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nAimant beaucoup trop grand\n[q]Lorsque Brann lance Outils de collecte , il a 100  % de chances de magnétiser des plaques métalliques abandonnées sur des membres du groupe, ce qui leur octroie un bouclier à hauteur de 5  % de leur maximum de points de vie qui se régénère hors combat.\n\n Outils de collecte\nBrann utilise ses outils de collecte pour aider les personnages-joueurs à trouver de l’or, du minerai, des plantes, des poissons, du cuir et des trésors supplémentaires.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][474574] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nDispositif de fusées bioalimenté\n[q]Les membres du groupe sont équipés |2 Dispositif de fusées bioalimenté .\n\n Biocarburant\n Chaque personnage adverse tué alimente le Dispositif de fusées bioalimenté , ce qui augmente la vitesse de déplacement de 2  % et la Hâte de 2  % pendant 10 s. Cumulable jusqu’à 10 fois.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][474576] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nBioimprimante tridimensionnelle\n[q]Lorsque vous infligez des dégâts à une créature élite disposant de moins de 40  % de ses points de vie, vous en créez une copie imparfaite dotée de 50  % de sa puissance et qui combat à vos côtés. Vous ne pouvez posséder que 1  copie simultanément.\n\n Il est possible que l’appareil présente des dysfonctionnements et crée des copies imparfaites de votre compagnon.\n\nVous disposez déjà de ce bibelot dans votre collection."}
