MultiLanguageSpellData['fr'][474582] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nAimant beaucoup trop grand\n[q]Lorsque Brann lance Outils de collecte , il a 100  % de chances de magnétiser des plaques métalliques abandonnées sur des membres du groupe, ce qui leur octroie un bouclier à hauteur de 10  % de leur maximum de points de vie qui se régénère hors combat.\n\n Outils de collecte\nBrann utilise ses outils de collecte pour aider les personnages-joueurs à trouver de l’or, du minerai, des plantes, des poissons, du cuir et des trésors supplémentaires.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][474583] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nAimant beaucoup trop grand\n[q]Lorsque Brann lance Outils de collecte , il a 100  % de chances de magnétiser des plaques métalliques abandonnées sur des membres du groupe, ce qui leur octroie un bouclier à hauteur de 15  % de leur maximum de points de vie qui se régénère hors combat.\n\n Outils de collecte\nBrann utilise ses outils de collecte pour aider les personnages-joueurs à trouver de l’or, du minerai, des plantes, des poissons, du cuir et des trésors supplémentaires.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][474584] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nAimant beaucoup trop grand\n[q]Lorsque Brann lance Outils de collecte , il a 100  % de chances de magnétiser des plaques métalliques abandonnées sur des membres du groupe, ce qui leur octroie un bouclier à hauteur de 20  % de leur maximum de points de vie qui se régénère hors combat.\n\n Outils de collecte\nBrann utilise ses outils de collecte pour aider les personnages-joueurs à trouver de l’or, du minerai, des plantes, des poissons, du cuir et des trésors supplémentaires.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][474585] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nBioimprimante tridimensionnelle\n[q]Lorsque vous infligez des dégâts à une créature élite disposant de moins de 40  % de ses points de vie, vous créez une copie imparfaite d’elle, dotée de 75  % de sa puissance, qui combat à vos côtés. Vous ne pouvez posséder que 1  copie simultanément.\n\n Il est possible que l’appareil présente des dysfonctionnements et crée des copies imparfaites de votre compagnon.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][474586] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nBioimprimante tridimensionnelle\n[q]Lorsque vous infligez des dégâts à une créature élite disposant de moins de 40  % de ses points de vie, vous créez une copie imparfaite d’elle, dotée de 75  % de sa puissance, qui combat à vos côtés. Vous ne pouvez posséder que 2  copie simultanément.\n\n Il est possible que l’appareil présente des dysfonctionnements et crée des copies imparfaites de votre compagnon.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][474587] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nBioimprimante tridimensionnelle\n[q]Lorsque vous infligez des dégâts à une créature élite disposant de moins de 40  % de ses points de vie, vous créez une copie imparfaite d’elle, dotée de 100  % de sa puissance, qui combat à vos côtés. Vous ne pouvez posséder que 2  copie simultanément.\n\n Il est possible que l’appareil présente des dysfonctionnements et crée des copies imparfaites de votre compagnon.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][474588] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nDispositif de fusées bioalimenté\n[q]Les membres du groupe sont équipés |2 Dispositif de fusées bioalimenté .\n\n Biocarburant\n Chaque personnage adverse tué alimente le Biocarburant , ce qui augmente la vitesse de déplacement de 2  % et la Hâte de 2  % pendant 20 s. Cumulable jusqu’à 15 fois.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][474589] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nDispositif de fusées bioalimenté\n[q]Les membres du groupe sont équipés |2 Dispositif de fusées bioalimenté .\n\n Biocarburant\n Chaque personnage adverse tué alimente le Biocarburant , ce qui augmente la vitesse de déplacement de 2  % et la Hâte de 2  % pendant 30 s. Cumulable jusqu’à 20 fois.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][474590] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nDispositif de fusées bioalimenté\n[q]Les membres du groupe sont équipés de Dispositif de fusées bioalimenté .\n\n Biocarburant\n Chaque personnage adverse tué alimente le dispositif de fusées, ce qui augmente la vitesse de déplacement de 2  % et la Hâte de 2  % pendant 45 s. Cumulable jusqu’à 30 fois.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][474591] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nMachine pacifiste\n[q]En combat, désigne un ou une pilote dans les 8 s, puis largue la machine pacifiste MK-2 sur sa position. Rend le personnage insensible, l’équipe de la machine et lui donne les commandes pendant 10 s. Cela repousse également les adversaires proches.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][474592] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nMachine pacifiste\n[q]En combat, désigne un ou une pilote dans les 8 s, puis largue la machine pacifiste MK-3 sur sa position. Rend le personnage insensible, l’équipe de la machine et lui donne les commandes pendant 10 s. Cela repousse également les adversaires proches.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][474593] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nMachine pacifiste\n[q]En combat, désigne un ou une pilote dans les 8 s, puis largue la machine pacifiste MK-4 sur sa position. Rend le personnage insensible, l’équipe de la machine et lui donne les commandes pendant 10 s. Cela repousse également les adversaires proches.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][474594] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nPylône surmultiplicateur\n[q]Après avoir passé 30  s en combat, Brann et les membres du groupe bénéficient d’un bonus de 10  % aux dégâts et aux soins pendant 30 s. Cet effet ne peut se produire qu’une fois par combat.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][474595] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nPylône surmultiplicateur\n[q]Après avoir passé 30  s en combat, Brann et les membres du groupe bénéficient d’un bonus de 15  % aux dégâts et aux soins pendant 30 s. Cet effet ne peut se produire qu’une fois par combat.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][474596] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nPylône surmultiplicateur\n[q]Après avoir passé 30  s en combat, Brann et les membres du groupe bénéficient d’un bonus de 20  % aux dégâts et aux soins pendant 40 s. Cet effet ne peut se produire qu’une fois par combat.\n\nVous disposez déjà de ce bibelot dans votre collection."}
