MultiLanguageSpellData['fr'][474599] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nKit de mécasaure facile à monter\n[q]Œuf épique de Brann contient désormais 1  mécasaure provoquant les cibles adverses pendant ( 4000 / 1000) s tant que l’éclosion n’a pas eu lieu.\n\n En plus des techniques habituelles, chaque mécasaure frappera le sol périodiquement, infligeant des dégâts de feu modérés répartis entre les adversaires proches. Les cibles adverses touchées explosent après 5 s et subissent des dégâts de feu modérés.\n\nŒuf épique de Brann\nBrann invoque un œuf de diablosaure. Espérons qu’il éclora.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][474600] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nDistributeur automatique de bomballes\n[q]Les sorts et techniques de Brann ont une chance de lâcher 2 bomballe sur le sol pendant 10 s.\n\n Courez sur l’une d’entre elles pour la projeter dans la direction d’une cible adverse, ce qui inflige des dégâts de feu importants à tous les personnages adverses dans un rayon de 6 m.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][474601] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nMatrice de conversion d’impact\n[q]En entrant en combat, Brann active la matrice de conversion pendant 10  s. Tant que l’effet est actif, un faible pourcentage de tous les dégâts infligés par le groupe est converti en caractéristique principale et réparti entre les membres du groupe.\n\n Lorsque la matrice de conversion s’éteint, le bonus à la caractéristique principale persiste pendant 10  s. Cet effet ne peut se produire plus d’une fois toutes les 2 min.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][474602] = {name = "Canon rugissant à déflagration", additional_info = "60 m de portée\nInstantanée\n[q]Fusendo suit une cible pendant qu’il charge, puis s’immobilise et se prépare à tirer. Une fois le canon prêt, il projette un rayon pendant 3 s. Ce rayon inflige 66606435 point de dégâts de feu toutes les 0.1 s aux personnages-joueurs au contact et les réduit en cendres."}
MultiLanguageSpellData['fr'][474603] = {name = "Appel de Pluméole", additional_info = nil}
MultiLanguageSpellData['fr'][474604] = {name = "Kill Credit - Runas Quests (NJS)", additional_info = nil}
MultiLanguageSpellData['fr'][474605] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nUsine de poche\n[q]Les sorts et techniques de Brann ont une chance de commander 1 tourelle à l’usine de poche en guise de soutien pendant 10 s.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][474606] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nGrenade goblomagnétique rebondissante\n[q]En combat, Brann a une chance de lancer une grenade GGR sur la cible adverse, laquelle subit alors des dégâts de nature modérés et a 20 % de chances d’être étourdie pendant 1.5 s. La grenade a 25 % de chances de rebondir sur une nouvelle cible.\n\n Elle peut également rebondir sur les membres du groupe sans leur infliger des dégâts ou les étourdir.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][474607] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nPuce d’augmentation pistée\n[q]Le maximum de points de vie de Brann augmente de 4  % et ses dégâts et soins de 20  %.\n\n En combat, des robots mécaniques pouvant être détruits ou dissipés ciblent parfois Brann et le traquent. Lorsqu’ils l’atteignent, Brann subit des dégâts à hauteur de 30  % de son maximum de points de vie et est étourdi pendant 5 s.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][474608] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nBombe mortelle gobeline à technologie inversée\n[q]En combat, lorsque les points de vie d’un personnage-joueur tombent sous 50 %, Brann lance une bombe géante qui explose à l’impact.\n\n L’explosion repousse et ralentit de 45 % les adversaires alentour pendant 5 s. En outre, elle rend 35 % de leur maximum de points de vie aux membres du groupe proches. Cet effet ne peut se produire qu’une fois toutes les 1.5 min.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][474609] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nPuce d’augmentation pistée\n[q]Le maximum de points de vie de Brann augmente de 6  % et ses dégâts et soins de 25  %.\n\n En combat, des robots mécaniques pouvant être détruits ou dissipés ciblent parfois Brann et le traquent. Lorsqu’ils l’atteignent, Brann subit des dégâts à hauteur de 30  % de son maximum de points de vie et est étourdi pendant 5 s.\n\nVous disposez déjà de ce bibelot dans votre collection."}
