MultiLanguageSpellData['fr'][1215713] = {name = "Ensemble de classe de guerrier ou guerrière Armes 11.1 (2 pièces)", additional_info = "Approximativement 10 activations par minute\n[q]Vos techniques ont une chance de lancer une Séquence victorieuse ! , ce qui augmente les dégâts de Fulgurance de 5 %, cumulable jusqu’à 10 fois.\n Fulgurance a 15 % de chances de mettre fin à votre Séquence victorieuse ! ."}
MultiLanguageSpellData['fr'][1215714] = {name = "Ensemble de classe de guerrier ou guerrière Fureur 11.1 (2 pièces)", additional_info = "Approximativement 10 activations par minute\n[q]Vos techniques ont une chance d’activer une Séquence victorieuse ! , ce qui augmente les dégâts de Saccage de 2 %, cumulable jusqu’à 10 fois.\n Saccage a 15 % de chances de mettre fin à votre Séquence victorieuse ! ."}
MultiLanguageSpellData['fr'][1215715] = {name = "Ensemble de classe de guerrier ou guerrière Fureur 11.1 (4 pièces)", additional_info = "[q]Lorsque vous obtenez une charge de Séquence victorieuse ! , vous avez une chance de permettre à votre prochaine technique Sanguinaire d’infliger 15 % de dégâts supplémentaires, avec 25 % de chances supplémentaires d’infliger un coup critique, ou bien de permettre à votre prochaine technique Coup déchaîné d’infliger 15 % de dégâts supplémentaires tout en générant 2 point de rage supplémentaires."}
MultiLanguageSpellData['fr'][1215716] = {name = "Ensemble de classe de guerrier ou guerrière Armes 11.1 (4 pièces)", additional_info = "[q]Quand votre Séquence victorieuse ! prend fin, vous obtenez 2 % de Hâte. Vos dégâts de Frappe mortelle et Enchaînement sont augmentés de 2 % par charge de Séquence victorieuse ! que vous aviez pendant 12 s."}
MultiLanguageSpellData['fr'][1215717] = {name = "Ensemble de classe de moine ou moniale Marche-vent 11.1 (2 pièces)", additional_info = "Approximativement 10 activations par minute\n[q]Vos sorts et techniques ont une chance d’activer une Séquence victorieuse ! , ce qui augmente les dégâts de Coup de pied du soleil levant et Coup tournoyant de la grue de 3 %, cumulable jusqu’à 10 fois. Coup de pied du soleil levant et Coup tournoyant de la grue ont 15 % de chances de mettre fin à votre Séquence victorieuse ! ."}
MultiLanguageSpellData['fr'][1215718] = {name = "Ensemble de classe de moine ou moniale Marche-vent 11.1 (4 pièces)", additional_info = "[q]Lorsque vous lancez Poings de fureur et après avoir fini de canaliser la technique, vous obtenez 1 charge de Séquence victorieuse ! . Les dégâts de votre prochaine technique Poings de fureur augmentent de 8 % par charge lorsque Séquence victorieuse ! prend fin.\n\n Votre Séquence victorieuse ! prend fin chaque fois que vous atteignez le maximum de charges."}
MultiLanguageSpellData['fr'][1215719] = {name = "Ensemble de classe de voleur ou voleuse Assassinat 11.1 (2 pièces)", additional_info = "Approximativement 10 activations par minute\n[q]Vos sorts et techniques ont une chance d’activer une Séquence victorieuse ! , ce qui augmente de 3 % les dégâts d’Envenimer, Rupture et Tempête cramoisie, cumulable jusqu’à 10 fois. Envenimer, Rupture et Tempête cramoisie ont 15 % de chances de mettre fin à votre Séquence victorieuse ! ."}
MultiLanguageSpellData['fr'][1215720] = {name = "Ensemble de classe de voleur ou voleuse Hors-la-loi 11.1 (2 pièces)", additional_info = "Approximativement 8 activations par minute\n[q]Vos sorts et techniques ont une chance d’activer une Séquence victorieuse ! , ce qui augmente les dégâts de Couperet de 6 %, cumulable jusqu’à 5 fois. Couperet a 15 % de chances de mettre fin à votre Séquence victorieuse ! ."}
MultiLanguageSpellData['fr'][1215721] = {name = "Ensemble de classe de voleur ou voleuse Finesse 11.1 (2 pièces)", additional_info = "Approximativement 10 activations par minute\n[q]Vos sorts et techniques ont une chance d’activer une Séquence victorieuse ! , ce qui augmente de 2 % les dégâts d’Éviscération, Technique secrète et Poudre noire, cumulable jusqu’à 8 fois. Éviscération, Technique secrète et Poudre noire ont 15 % de chances de mettre fin à votre Séquence victorieuse ! ."}
MultiLanguageSpellData['fr'][1215722] = {name = "Ensemble de classe de voleur ou voleuse Finesse 11.1 (4 pièces)", additional_info = "[q]Lorsque Danse de l’ombre est active, vous ne pouvez pas perdre Séquence victorieuse ! , vous gagnez une charge supplémentaire de Séquence victorieuse ! chaque fois que vous devez en gagner une et vous infligez 2 % de dégâts d’ombre supplémentaires par charge de Séquence victorieuse ! ."}
MultiLanguageSpellData['fr'][1215724] = {name = "Ensemble de classe de voleur ou voleuse Assassinat 11.1 (4 pièces)", additional_info = "[q]Au moment où vous devriez perdre Séquence victorieuse ! , vous avez une chance de gagner à la place le maximum de charges de Séquence victorieuse ! pendant 4 s. Ces charges ne peuvent pas être supprimées et ont 50 % d’effet supplémentaire tant qu’elles sont insensibles à la suppression."}
MultiLanguageSpellData['fr'][1215725] = {name = "Ensemble de classe de voleur ou voleuse Hors-la-loi 11.1 (4 pièces)", additional_info = "[q]Jet d’osselets a 40 % de chances de conférer des améliorations de combat supplémentaires et octroie 1 charge de Séquence victorieuse ! par amélioration de combat obtenue.\n\n Les charges octroyées par Jet d’osselets peuvent dépasser la limite maximale habituelle de 5 de la Séquence victorieuse ! ."}
