MultiLanguageSpellData['fr'][1215727] = {name = "Ensemble de classe de chevalier ou chevalière de la mort Givre 11.1 (2 pièces)", additional_info = "Approximativement 10 activations par minute\n[q]Vos sorts et techniques ont une chance d’activer une Séquence victorieuse ! , ce qui augmente de 4 % les dégâts de Frappe de givre et Avancée glaciale, cumulable jusqu’à 6 fois. Frappe de givre et Avancée glaciale ont 7 % de chances de mettre fin à votre Séquence victorieuse ! ."}
MultiLanguageSpellData['fr'][1215728] = {name = "Ensemble de classe de chevalier ou chevalière de la mort Impie 11.1 (4 pièces)", additional_info = "[q]Le fait de lancer Sombre transformation confère jusqu’à 10 charges de Séquence victorieuse ! . Tant que Sombre transformation est active, votre Séquence victorieuse ! gagne 100 % d’efficacité et ne peut plus se réinitialiser."}
MultiLanguageSpellData['fr'][1215729] = {name = "Ensemble de classe de chevalier ou chevalière de la mort Givre 11.1 (4 pièces)", additional_info = "[q]Séquence victorieuse ! permet à Frappe de givre et Avancée glaciale d’avoir 8 % de chances par charge de lancer Faux de givre à 30 % d’efficacité. Le fait de perdre Séquence victorieuse ! vous plonge dans une frénésie meurtrière, lançant Faux de givre à 100 % d’efficacité et vous conférant (6 * $mastery) % de Maîtrise pendant 6 s. De plus, Faux de givre inflige 40 % de dégâts supplémentaires à la première cible touchée."}
