MultiLanguageSpellData['fr'][1217236] = {name = "Séquence victorieuse !", additional_info = "Instantanée\n[q]Vos sorts et techniques ont une chance d’activer une Séquence victorieuse ! , ce qui augmente les dégâts de Morsure féroce, Déchirure et Colère primitive de 3 %, cumulable jusqu’à 10 fois. Morsure féroce, Déchirure et Colère primitive ont 15 % de chances de mettre fin à votre Séquence victorieuse ! . Les Morsures féroces gratuites ne sont pas prises en compte dans les chances de désactivation.\n(Chance d'occurence :15%)"}
