MultiLanguageSpellData['fr'][1218300] = {name = "Sélection rétrécissante de Brouillecaboche", additional_info = "{Instantanée} {0.5 s de recharge}\n[q]Réduit légèrement la taille. Cumulable jusqu’à 10 fois."}
MultiLanguageSpellData['fr'][1218301] = {name = "Prototype de publicité automatique", additional_info = "8 m de portée\n{Instantanée} {5 min de recharge}\n[q]Vous placez une publicité automatique, ce qui a pour effet d’énerver au plus haut point toutes les créatures proches et augmente les dégâts qu’elles vous infligent de 50 % pendant 3 min.\n\n Utilisable uniquement à Terremine. Les personnages adverses laissent tomber des études de marché supplémentaires pour la lanceur ou la lanceuse pendant que l’effet est actif."}
MultiLanguageSpellData['fr'][1218302] = {name = "Perforation", additional_info = "100 m de portée\nInstantanée\n[q]Le corps épineux de Giovante vous transperce, provoquant un saignement qui inflige des dégâts physiques toutes les 2 s pendant 12 s. Cet effet est cumulable."}
MultiLanguageSpellData['fr'][1218303] = {name = "Générateur de bouclier", additional_info = nil}
MultiLanguageSpellData['fr'][1218304] = {name = "Prototype de publicité automatique", additional_info = "100 m de portée\nInstantanée\n[q]Vous placez une publicité automatique, ce qui a pour effet d’énerver au plus haut point toutes les créatures proches et augmente les dégâts qu’elles vous infligent de 50 % pendant 3 min.\n\n Utilisable uniquement à Terremine. Les personnages adverses laissent tomber des études de marché supplémentaires pour la lanceur ou la lanceuse pendant que l’effet est actif."}
MultiLanguageSpellData['fr'][1218305] = {name = "Étalon forgé par le Vide", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie cette monture.\n[q]\"Forgées comme leurs sabots l’étaient autrefois, ces bêtes ne sont plus vraiment des chevaux, mais plutôt un agrégat d’énergie du Vide ayant pris leur forme.\"\nButin :\nétalon forgé par le Vide\nRégion :\nvision de Hurlevent (redécouverte)"}
MultiLanguageSpellData['fr'][1218306] = {name = "Mère de meute marquée par le Vide", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie cette monture.\n[q]\"En attaquant les gens corrompus chargés de son dressage, cette mère avait pu libérer ses petits. Mais cette fuite ne les avait pas libérés du Vide qui régnait dans ce lieu perdu. Elle a élevé ses petits pour en faire des bêtes encore plus dangereuses, qui rôdent à présent dans Orgrimmar en quête de la nourriture qui leur permettra de survivre un jour de plus.\"\nButin :\nmère de meute marquée par le Vide\nRégion :\nvision d’Orgrimmar (redécouverte)"}
MultiLanguageSpellData['fr'][1218307] = {name = "Coursier du vent marqué par le Vide", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie cette monture.\n[q]\"Lorsque l’énergie du Vide fut libérée, elle fit échapper la plupart des coursiers du vent à tout contrôle. Ils se retournèrent contre les gens chargés de leur dressage, puis les uns contre les autres. Les rares âmes qui purent s’en tirer verrouillèrent les portes de leur couvoir. On voit encore quelques coursiers du vent planer dans le ciel, mais personne n’ose braver les dangers de leur territoire pour voir ce qu’il en reste.\"\nButin :\ncoursier du vent marqué par le Vide\nRégion :\nvision d’Orgrimmar (redécouverte)"}
MultiLanguageSpellData['fr'][1218308] = {name = "Fournaise d’embrasement", additional_info = "Instantanée\n[q]Blazikon propulse un souffle ardent vers chaque bougie éteinte afin de la rallumer. Le souffle inflige 8487876 point de dégâts de feu à tous les personnages-joueurs sur sa trajectoire.\n\n Le brasier brûle tous les personnages-joueurs, infligeant 242445 point de dégâts de feu toutes les 1 s pendant 8 s. Cet effet est cumulable."}
MultiLanguageSpellData['fr'][1218310] = {name = "Modèle de test d’électroperforation", additional_info = "30 m de portée\n{2 s d'incantation} {10 min de recharge}\n[q]Vous envoyez un courant revigorant à travers la cible, ce qui augmente la Hâte de 20 %, réduit les dégâts subis de 25 % et provoque des dégâts de nature autour d’elle pendant 3 min.\n\n Utilisable sur la plupart des créatures rares de Terremine. La cible laisse tomber des études de marché supplémentaires pour tous les personnages-joueurs tant que l’effet est actif."}
MultiLanguageSpellData['fr'][1218311] = {name = "Sélection stylée de Brouillecaboche", additional_info = "{Instantanée} {0.5 s de recharge}\n[q]Vous avez temporairement un certain style."}
MultiLanguageSpellData['fr'][1218313] = {name = "Allumer", additional_info = nil}
MultiLanguageSpellData['fr'][1218314] = {name = "Ver d’ombre de Ny’alotha", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie votre ver d’ombre de Ny’alotha.\n[q]\"Vestige du passé de l’Empire noir, ces ancêtres des vers abyssaux font leur retour avec l’ascension de Ny’alotha.\"\nHaut fait :\nMaîtrise des visionsCatégorie :\nVisions de N’Zoth redécouvertes"}
MultiLanguageSpellData['fr'][1218315] = {name = "Modèle de test d’électroperforation", additional_info = "20 m de portée\nInstantanée\n[q]Inflige 7 point de dégâts de nature."}
MultiLanguageSpellData['fr'][1218316] = {name = "Corruption des Aspects", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie la Corruption des Aspects. Cette monture change en fonction de votre compétence de monte et de l’endroit où vous vous trouvez.\n[q]\"Grâce au triomphe de N’Zoth, ce qui avait commencé avec Galakrond porta ses fruits et, une fois les Aspects disparus, la corruption de leur espèce fut totale.\"\nVendeuse :\nTorie\nRégion :\nDornogal\nCoût :\n40 000"}
MultiLanguageSpellData['fr'][1218317] = {name = "Panthère en cristal du Vide", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie une panthère en cristal du Vide.\n[q]\"Bien des gemmes précieuses ont été corrompues par les énergies du Vide dans des visions horrifiques, mais les spécialistes en joaillerie peuvent toujours les utiliser pour créer de puissantes panthères de monte.\"\nMétier :\njoaillerie"}
