MultiLanguageSpellData['fr'][1224766] = {name = "Diffuseurs de toiles", additional_info = "Instantanée\n[q]Les diffuseurs de toiles sont entourés de toiles. Le fait de se tenir dans celles-ci réduit la vitesse de déplacement et fait régulièrement apparaître des embusqués. Vous pouvez attaquer les diffuseurs de toiles pour temporairement réduire la taille de la zone."}
MultiLanguageSpellData['fr'][1224767] = {name = "Servitude du roi", additional_info = "Portée illimitée\nInstantanée\n[q]Un personnage-joueur succombe à son serment et se retrouve sous emprise mentale pendant 12 s. Le Vide le renforce, lui rendant tous ses points de vie.\n\n À la fin de l’effet, le personnage contrôlé explose et inflige 100 point de dégâts d’ombre à tous les personnages-joueurs."}
MultiLanguageSpellData['fr'][1224775] = {name = "Collier de dévotion", additional_info = "[q]Vous faites partie des êtres dévots. Augmente l’efficacité de Protection de la Flamme sacrée de 100 %.\n\nProtection de la Flamme sacrée  :\nEn Khaz Algar, les dégâts infligés ont de fortes chances de brûler le personnage adverse avec un feu vertueux infligeant 2 point de dégâts de rayonnement. De plus, les dégâts subis sont réduits de 5 %."}
