MultiLanguageSpellData['fr'][1224959] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nConvertisseur d’énergie éthérien\n[q]Lorsqu’un membre du groupe tombe sous 60  % de points de vie, un convertisseur d’énergie éthérien se matérialise, ce qui inflige des dégâts modérés aux adversaires proches et les provoque pendant 4  s. Lorsque la raillerie prend fin, le convertisseur libère une onde éthérée qui soigne les personnages alliés proches de 20  % de leurs points de vie. Cet effet ne peut être déclenché qu’une fois toutes les 2 min. Le fait de tuer des adversaires réduit le temps de recharge de cet effet de 2  s.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][1224961] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nConvertisseur d’énergie éthérien\n[q]Lorsqu’un membre du groupe tombe sous 60 % de points de vie, un convertisseur d’énergie éthérien se matérialise, ce qui inflige des dégâts modérés aux adversaires proches et les provoque pendant 4 s. Lorsque la raillerie prend fin, le convertisseur libère une onde éthérée qui soigne les personnages alliés proches de 30 % de leurs points de vie. Cet effet ne peut être déclenché qu’une fois toutes les 2 min. Le fait de tuer des adversaires réduit le temps de recharge de cet effet de 4 s.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][1224962] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nConvertisseur d’énergie éthérien\n[q]Lorsqu’un membre du groupe tombe sous 60 % de points de vie, un convertisseur d’énergie éthérien se matérialise, ce qui inflige des dégâts modérés aux adversaires proches et les provoque pendant 6 s. Lorsque la raillerie prend fin, le convertisseur libère une onde éthérée qui soigne les personnages alliés proches de 40 % de leurs points de vie. Cet effet ne peut être déclenché qu’une fois toutes les 2 min. Le fait de tuer des adversaires réduit le temps de recharge de cet effet de 6 s.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][1224963] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nConvertisseur d’énergie éthérien\n[q]Lorsqu’un membre du groupe tombe sous 60 % de points de vie, un convertisseur d’énergie éthérien se matérialise, ce qui inflige des dégâts modérés aux adversaires proches et les provoque pendant 6 s. Lorsque la raillerie prend fin, le convertisseur libère une onde éthérée qui soigne les personnages alliés proches de 50 % de leurs points de vie. Cet effet ne peut être déclenché qu’une fois toutes les 2 min. Le fait de tuer des adversaires réduit le temps de recharge de cet effet de 8 s.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][1224964] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nLunettes teintées au mana\n[q]Brann revêt des lunettes teintées au mana lorsqu’il est en combat, ce qui augmente périodiquement les dégâts qu’il inflige de 4 % et les dégâts qu’il subit de 5 % toutes les 5 s, cumulable 10 fois.\n\n Le fait de lui retirer les lunettes le soigne de 25 % de son maximum de points de vie et étourdit les personnages adverses proches pendant 2 s.\n Sinon, cet effet est automatiquement dissipé lorsque Brann tombe sous 30 % de points de vie, ce qui empêche l’effet d’étourdissement de se produire.\n\nVous disposez déjà de ce bibelot dans votre collection."}
