MultiLanguageSpellData['fr'][1224968] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nLunettes teintées au mana\n[q]Brann revêt des lunettes teintées au mana lorsqu’il est en combat, ce qui augmente périodiquement les dégâts qu’il inflige de 5 % et les dégâts qu’il subit de 5 % toutes les 5 s, cumulable 10 fois.\n\n Le fait de lui retirer les lunettes le soigne de 70 % de son maximum de points de vie et étourdit les personnages adverses proches pendant 5 s.\n Sinon, cet effet est automatiquement dissipé lorsque Brann tombe sous 30 % de points de vie, ce qui empêche l’effet d’étourdissement de se produire.\n\nVous disposez déjà de ce bibelot dans votre collection."}
