MultiLanguageSpellData['fr'][1225038] = {name = "Dévastation du Crépuscule", additional_info = "Instantanée\nApproximativement 1 activations par minute\n[q]Applique une rune inférieure de dévastation du Crépuscule sur une pièce d’armure de tête.\n\n Vos attaques ont une chance de déclencher un rayon de Dévastation du Crépuscule, ce qui inflige ( 1 * 845195 * 3) point de dégâts d’ombre aux adversaires devant vous.\n\n Ne peut être appliqué sur des objets d’un niveau inférieur à 350. Cet effet est éphémère et n’est effectif que pendant la saison 2 de The War Within.\n(4sec de recharge)"}
