MultiLanguageSpellData['fr'][1225065] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nCristal de décélération temporelle\n[q]Le fait d’infliger des dégâts à une créature élite ayant plus de 80 % ou moins de 20 % de points de vie permet à Brann de libérer les énergies du cristal, ce qui réduit la vitesse d’attaque et d’incantation de la créature de 20 % pendant 30 s. Lorsque la créature élite ciblée est tuée alors que l’affaiblissement est actif, le groupe bénéficie d’un bonus cumulable de Hâte de 2 %.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][1225066] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nCristal de décélération temporelle\n[q]Le fait d’infliger des dégâts à une créature élite ayant plus de 80 % ou moins de 20 % de points de vie permet à Brann de libérer les énergies du cristal, ce qui réduit la vitesse d’attaque et d’incantation de la créature de 30 % pendant 30 s. Lorsque la créature élite ciblée est tuée alors que l’affaiblissement est actif, le groupe bénéficie d’un bonus cumulable de Hâte de 4 %.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][1225067] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nCristal de décélération temporelle\n[q]Le fait d’infliger des dégâts à une créature élite ayant plus de 80 % ou moins de 20 % de points de vie permet à Brann de libérer les énergies du cristal, ce qui réduit la vitesse d’attaque et d’incantation de la créature de 40 % pendant 30 s. Lorsque la créature élite ciblée est tuée alors que l’affaiblissement est actif, le groupe bénéficie d’un bonus cumulable de Hâte de 6 %.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][1225068] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nCristal de décélération temporelle\n[q]Le fait d’infliger des dégâts à une créature élite ayant plus de 80 % ou moins de 20 % de points de vie permet à Brann de libérer les énergies du cristal, ce qui réduit la vitesse d’attaque et d’incantation de la créature de 50 % pendant 30 s. Lorsque la créature élite ciblée est tuée alors que l’affaiblissement est actif, le groupe bénéficie d’un bonus cumulable de Hâte de 8 %.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][1225069] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nÉgide endommagée\n[q]Lorsque l’égide est portée, augmente et les dégâts et les soins des membres du groupe de 3 %. En combat et toutes les 10 s, Brann et vous vous soignez d’un montant égal à 5 % des dégâts subis pendant ce laps de temps.\n\n Lorsqu’un personnage-joueur meurt, l’égide lui accorde une réduction des dégâts de 1 % et un bonus aux soins reçus de 2 % à la réanimation, mais réduit les dégâts et soins produits de 1 %. Cumulable jusqu’à 3 fois.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][1225070] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nÉgide endommagée\n[q]Lorsque l’égide est portée, augmente et les dégâts et les soins des membres du groupe de 6 %. En combat et toutes les 10 s, Brann et vous vous soignez d’un montant égal à 10 % des dégâts subis pendant ce laps de temps.\n\n Lorsqu’un personnage-joueur meurt, l’égide lui accorde une réduction des dégâts de 2 % et un bonus aux soins reçus de 3 % à la réanimation, mais réduit les dégâts et soins produits de 2 %. Cumulable jusqu’à 3 fois.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][1225072] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nÉgide endommagée\n[q]Lorsque l’égide est portée, augmente et les dégâts et les soins des membres du groupe de 9 %. En combat et toutes les 10 s, Brann et vous vous soignez d’un montant égal à 15 % des dégâts subis pendant ce laps de temps.\n\n Lorsqu’un personnage-joueur meurt, l’égide lui accorde une réduction des dégâts de 3 % et un bonus aux soins reçus de 4 % à la réanimation, mais réduit les dégâts et soins produits de 3 %. Cumulable jusqu’à 3 fois.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][1225073] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nÉgide endommagée\n[q]Lorsque l’égide est portée, augmente et les dégâts et les soins des membres du groupe de 12 %. En combat et toutes les 10 s, Brann et vous vous soignez d’un montant égal à 20 % des dégâts subis pendant ce laps de temps.\n\n Lorsqu’un personnage-joueur meurt, l’égide lui accorde une réduction des dégâts de 4 % et un bonus aux soins reçus de 5 % à la réanimation, mais réduit les dégâts et soins produits de 4 %. Cumulable jusqu’à 3 fois.\n\nVous disposez déjà de ce bibelot dans votre collection."}
MultiLanguageSpellData['fr'][1225074] = {name = "Rune inférieure de dévastation du Crépuscule", additional_info = "3.5 s d'incantation\nRequiert Armure\n[q]Applique une rune inférieure de dévastation du Crépuscule sur une pièce d’armure de tête.\n\n Vos attaques ont une chance de déclencher un rayon de Dévastation du Crépuscule, ce qui inflige ( 1 * 845195 * 3) point de dégâts d’ombre aux adversaires devant vous.\n\n Ne peut être appliqué sur des objets d’un niveau inférieur à 350. Cet effet est éphémère et n’est effectif que pendant la saison 2 de The War Within."}
MultiLanguageSpellData['fr'][1225076] = {name = "Ajout", additional_info = "1.5 s d'incantation\nComposants:\nCristal d’amplification audio\n[q]La voix de Brann est légèrement amplifiée à l’aide de magie arcanique, ce qui permet à ses paroles d’octroyer un bonus au groupe en fonction de ce qu’il dit.\n\nVous disposez déjà de ce bibelot dans votre collection."}
