MultiLanguageSpellData['fr'][1226441] = {name = "Rupture du néant", additional_info = "Portée illimitée\nInstantanée\n[q]Des amas de roches s’abattent au sol, ce qui inflige 801626 point de dégâts physiques aux personnages-joueurs à moins de 11 m de l’impact.\n\n Les failles du Vide persistent pendant 20 s et attirent les personnages-joueurs à portée, ce qui leur applique [Corruption du Vide] toutes les 1 s."}
