MultiLanguageSpellData['fr'][1226487] = {name = "Grand bâton de focalisation", additional_info = "Portée illimitée\nInstantanée\n[q]Provoque la colère de l’arme de Diurna et consomme une charge de Courroux du grand bâton. L’arme libère un rayon concentré d’énergie de la tempête dans le sol, qui poursuite le personnage-joueur et inflige 20  points de dégâts de nature aux personnages-joueurs à moins de 3 mètres toutes les demi-secondes pendant la poursuite."}
MultiLanguageSpellData['fr'][1226488] = {name = "Gigabombe déchargée", additional_info = "Portée illimitée\nInstantanée\n[q]Inflige 922360 point de dégâts de nature toutes les 3 s aux 5 personnages-joueurs les plus proches.\n\n À l’interaction, confère Gigabombe déchargée et subit à la place 922360 points de dégâts de nature toutes les 1.5 s. Cet effet est cumulable."}
MultiLanguageSpellData['fr'][1226489] = {name = "Fusées surchargées", additional_info = "Portée illimitée\nInstantanée\n[q]L’explosion attache des fusées surchargées sur des imbéciles qui ne se doutaient de rien pendant 6 s .\n\n À la fin de l’effet, ces fusées partent dans les directions indiquées infligeant 2934780 point de dégâts de feu chaque seconde pendant 9 s aux personnages-joueurs impactés, tout en les repoussant."}
