MultiLanguageSpellData['fr'][1226531] = {name = "Porc-épic glaneur d’été", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie cette monture.\n[q]\"Le porc-épic d’été aime s’allonger au soleil ou nager dans un lac tranquille. Il n’a pas son pareil pour dénicher de la nourriture, mais il faut le convaincre d’en faire l’effort.\"\nComptoir"}
MultiLanguageSpellData['fr'][1226532] = {name = "Porc-épic glaneur d’hiver", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie cette monture.\n[q]\"Les porcs-épics d’hiver sont des créatures nocturnes. Un peu plus lents que les autres porcs-épics, ils ont en revanche une endurance sans égale.\"\nComptoir"}
MultiLanguageSpellData['fr'][1226533] = {name = "Porc-épic glaneur d’automne", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie cette monture.\n[q]\"Les porcs-épics d’automne sont très doués pour trouver de la nourriture dans les mois froids de l’année. Leur odorat très développé en fait d’excellents compagnons en forêt, mais difficiles à contrôler dans les environnements les plus riches en odeurs.\"\nComptoir"}
