MultiLanguageSpellData['fr'][1226650] = {name = "[q3]Panthère en cristal du Vide", additional_info = "2 s d'incantation 2\nOutils: Outils de joaillerie\nComposants:\nOrbe de mystère lié par le Vide , Gemmes insolites , Onyx imprégné d’ombre (20), Lingot imprégné de Sang noir (4)\nButin :\nGrand Pan Su\nRégion :\nvision d’Orgrimmar\n\n[q3]Panthère en cristal du Vide\n[q7]Lié au bataillon\nMonture[q0](Portant sur le compte)\n[q2]Utilise: Vous apprend à invoquer cette monture. Elle change selon l’endroit où vous vous trouvez et votre compétence de monte.\n[q2]Invoque et renvoie une panthère en cristal du Vide.\n1 - 80 ( 80)\nRequiertApprenti cavalier\n[q]\"Bien des gemmes précieuses ont été corrompues par les énergies du Vide dans des visions horrifiques, mais les spécialistes en joaillerie peuvent toujours les utiliser pour créer de puissantes panthères de monte.\"\nMétier :\njoaillerie"}
MultiLanguageSpellData['fr'][1226659] = {name = "Étoile noire", additional_info = "Portée illimitée\nInstantanée\n[q]Une étoile se matérialise depuis le Néant distordu, attirant les personnages-joueurs vers son centre pendant 5 s.\n\n À son apparition, les personnages-joueurs se tenant dans l’ Étoile noire subissent Atomisation et des Piques du crépuscule jaillissent. Inflige 56215 point de dégâts cosmiques à tous les personnages-joueurs toutes les 1 s."}
MultiLanguageSpellData['fr'][1226660] = {name = "Étoile noire", additional_info = "Portée illimitée\nInstantanée\n[q]Une étoile se matérialise depuis le Néant distordu, attirant les personnages-joueurs vers son centre pendant 5 s.\n\n À son apparition, les personnages-joueurs se tenant dans l’ Étoile noire subissent Atomisation et des Piques du crépuscule jaillissent. Inflige 56215 point de dégâts cosmiques à tous les personnages-joueurs toutes les 1 s."}
