MultiLanguageSpellData['fr'][1226969] = {name = "Souffle de Sindragosa", additional_info = "Instantanée\n[q]Vous infligez en continu [([139.788% of Attack Power]) * [(Puissance d'attaque * 0.98)][((Puissance d'attaque + [Offhand Attack Power]) * 2 / 3)] -- 2H, DW / Puissance d'attaque] points de dégâts de Givre toutes les 1 s aux ennemis dans un cône devant vous, jusqu’à ce que votre puissance runique soit épuisée. Inflige des dégâts réduits aux cibles secondaires.\n\nGénère 1 rune au début et à la fin."}
MultiLanguageSpellData['fr'][1226983] = {name = "Grand corbeau de l’archimage", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie le grand corbeau de l’archimage.\n[q]\"Peut-être un peu plus vieux et gris qu’une nuit sombre traditionnelle, ce corbeau représente néanmoins l’un des maîtres arcaniques les plus puissants d’Azeroth, Khadgar le gardien.\"\nBoutique en jeu"}
