MultiLanguageSpellData['fr'][1229185] = {name = "Convertisseur d’énergie éthérien", additional_info = "[q]Lorsqu’un membre du groupe tombe sous 60 % de points de vie, un convertisseur d’énergie éthérien se matérialise, ce qui inflige des dégâts modérés aux adversaires proches et les provoque pendant 4 s. Lorsque la raillerie prend fin, le convertisseur libère une onde éthérée qui soigne les personnages alliés proches de 20 % de leurs points de vie. Cet effet ne peut être déclenché qu’une fois toutes les 2 min. Le fait de tuer des adversaires réduit le temps de recharge de cet effet de 2 s."}
MultiLanguageSpellData['fr'][1229186] = {name = "Convertisseur d’énergie éthérien", additional_info = "[q]Lorsqu’un membre du groupe tombe sous 60 % de points de vie, un convertisseur d’énergie éthérien se matérialise, ce qui inflige des dégâts modérés aux adversaires proches et les provoque pendant 4 s. Lorsque la raillerie prend fin, le convertisseur libère une onde éthérée qui soigne les personnages alliés proches de 30 % de leurs points de vie. Cet effet ne peut être déclenché qu’une fois toutes les 2 min. Le fait de tuer des adversaires réduit le temps de recharge de cet effet de 4 s."}
MultiLanguageSpellData['fr'][1229187] = {name = "Convertisseur d’énergie éthérien", additional_info = "[q]Lorsqu’un membre du groupe tombe sous 60 % de points de vie, un convertisseur d’énergie éthérien se matérialise, ce qui inflige des dégâts modérés aux adversaires proches et les provoque pendant 6 s. Lorsque la raillerie prend fin, le convertisseur libère une onde éthérée qui soigne les personnages alliés proches de 40 % de leurs points de vie. Cet effet ne peut être déclenché qu’une fois toutes les 2 min. Le fait de tuer des adversaires réduit le temps de recharge de cet effet de 6 s."}
