MultiLanguageSpellData['fr'][1229189] = {name = "Lunettes teintées au mana", additional_info = "[q]Brann revêt des lunettes teintées au mana lorsqu’il est en combat, ce qui augmente périodiquement les dégâts qu’il inflige de 4 % et les dégâts qu’il subit de 5 % toutes les 5 s, cumulable 10 fois.\n\n Le fait de lui retirer les lunettes le soigne de 25 % de son maximum de points de vie et étourdit les personnages adverses proches pendant 2 s.\n Sinon, cet effet est automatiquement dissipé lorsque Brann tombe sous 30 % de points de vie, ce qui empêche l’effet d’étourdissement de se produire."}
MultiLanguageSpellData['fr'][1229190] = {name = "Lunettes teintées au mana", additional_info = "[q]Brann revêt des lunettes teintées au mana lorsqu’il est en combat, ce qui augmente périodiquement les dégâts qu’il inflige de 4 % et les dégâts qu’il subit de 5 % toutes les 5 s, cumulable 10 fois.\n\n Le fait de lui retirer les lunettes le soigne de 40 % de son maximum de points de vie et étourdit les personnages adverses proches pendant 3 s.\n Sinon, cet effet est automatiquement dissipé lorsque Brann tombe sous 30 % de points de vie, ce qui empêche l’effet d’étourdissement de se produire."}
