MultiLanguageSpellData['fr'][1229197] = {name = "Bout-de-rang", additional_info = "[q]Brann a une chance de sortir des chapeaux aléatoires et de les lancer sur les personnages adverses, leur infligeant des dégâts modérés et appliquant 1 affaiblissement à 2 cible.\n\n Les affaiblissements possibles comprennent une augmentation des dégâts subis de 20 %, une réduction des dégâts infligés de 20 % et une réduction de la vitesse d’attaque et d’incantation de 20 %."}
