MultiLanguageSpellData['fr'][1233539] = {name = "Dévorer", additional_info = "2 s d'incantation\n[q]À 100 points d’énergie, Dimensius augmente sa densité et crée une puissante force d’attraction qui inflige 1686460 point de dégâts d’ombre toutes les 1 pendant 5 s et attire les personnages-joueurs, les étoiles du Vide, les trous noirs et le disque d’accrétion.\n\n Au bout de 5 s, tous les personnages-joueurs se trouvant hors d’un Puits de gravité d’une étoile du Vide sont immédiatement engloutis par Dimensius et envoyés dans l’ Oubli ."}
MultiLanguageSpellData['fr'][1233542] = {name = "Le Geleur d’Ossements", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie cette monture.\n[q]\"Amer rival du Fondeur d’Ossements, ce rampant fut chassé de son antre près de la manaforge Oméga après une défaite écrasante. Il cherche à présent à s’instruire auprès de l’individu qui a détrôné son ennemi juré.\"\nFaction :\nVandales de la manaforge\nRenom :\n14\nRégion :\ncap de l’Ombre"}
