MultiLanguageSpellData['fr'][1233546] = {name = "Rampant du Vide rubis", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie cette monture.\n[q]\"« Recueilli » par l’Entente de K’aresh à des fins d’étude, ce rampant du Vide est une monture à la vigueur remarquable.\""}
MultiLanguageSpellData['fr'][1233547] = {name = "Rampant du Vide acide", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie cette monture.\n[q]\"Ce rampant a absorbé des vapeurs nocives qui ont imprégné son corps d’acides puissants.\"\nVendeuse :\nShad’anis\nRégion :\nK’aresh\nCoût :\n7"}
