MultiLanguageSpellData['fr'][1233553] = {name = "Prisme néantin inflexible", additional_info = "[q]Vos techniques néfastes puisent du Vide focalisé dans le prisme pour infliger ( 441 * 1 ) point de dégâts cosmiques répartis entre votre cible et les adversaires proches. Dégâts augmentés de 30 % par cible touchée, jusqu’à un maximum de 150 %. Cet effet peut se produire toutes les 10 s et accumule de la puissance latente dans le prisme, jusqu’à un maximum de 18 fois.\n(10sec de recharge)"}
MultiLanguageSpellData['fr'][1233556] = {name = "Prisme néantin inflexible", additional_info = "{Instantanée} {20 s de recharge}\n[q]Vous consommez toute la puissance latente pour gagner un bonus de 18 par cumul à la Force ou l’Agilité pendant 20 s."}
