MultiLanguageSpellData['fr'][1233559] = {name = "Barry le Bleu", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie cette monture.\n[q]\"Variante particulièrement rare d’ardospine, « Barry le Bleu » était auparavant une bête de somme.\"\nQuête :\nUn beau bleu\nRégion :\nK’aresh"}
MultiLanguageSpellData['fr'][1233561] = {name = "Ardospine curieuse", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie cette monture.\n[q]\"Cette ardospine curieuse a réussi à se coincer dans une boîte. Allez savoir comment elle a fait pour y entrer.\"\nButin :\ncache du sommet frétillante\nRégion :\nK’aresh"}
