MultiLanguageSpellData['fr'][1233654] = {name = "Lunettes teintées au mana", additional_info = "Portée illimitée\nInstantanée\n[q]Brann revêt des lunettes teintées au mana lorsqu’il est en combat, ce qui augmente périodiquement les dégâts qu’il inflige de 4 % et les dégâts qu’il subit de 5 % toutes les 5 s, cumulable 10 fois.\n\n Le fait de lui retirer les lunettes le soigne de 40 % de son maximum de points de vie et étourdit les personnages adverses proches pendant 3 s.\n Sinon, cet effet est automatiquement dissipé lorsque Brann tombe sous 30 % de points de vie, ce qui empêche l’effet d’étourdissement de se produire."}
MultiLanguageSpellData['fr'][1233655] = {name = "Lunettes teintées au mana", additional_info = "Portée illimitée\nInstantanée\n[q]Brann revêt des lunettes teintées au mana lorsqu’il est en combat, ce qui augmente périodiquement les dégâts qu’il inflige de 5 % et les dégâts qu’il subit de 5 % toutes les 5 s, cumulable 10 fois.\n\n Le fait de lui retirer les lunettes le soigne de 55 % de son maximum de points de vie et étourdit les personnages adverses proches pendant 4 s.\n Sinon, cet effet est automatiquement dissipé lorsque Brann tombe sous 30 % de points de vie, ce qui empêche l’effet d’étourdissement de se produire."}
MultiLanguageSpellData['fr'][1233656] = {name = "Lunettes teintées au mana", additional_info = "Portée illimitée\nInstantanée\n[q]Brann revêt des lunettes teintées au mana lorsqu’il est en combat, ce qui augmente périodiquement les dégâts qu’il inflige de 5 % et les dégâts qu’il subit de 5 % toutes les 5 s, cumulable 10 fois.\n\n Le fait de lui retirer les lunettes le soigne de 70 % de son maximum de points de vie et étourdit les personnages adverses proches pendant 5 s.\n Sinon, cet effet est automatiquement dissipé lorsque Brann tombe sous 30 % de points de vie, ce qui empêche l’effet d’étourdissement de se produire."}
MultiLanguageSpellData['fr'][1233657] = {name = "Prisme du Néant", additional_info = "Instantanée\n[q]Six cristaux sombres émettent Entropie réfractée sur une ligne en direction de Fractillus, infligeant 703583 point de dégâts d’ombre toutes les 0.5 s aux personnages-joueurs au contact avec l’effet."}
MultiLanguageSpellData['fr'][1233659] = {name = "Bout-de-rang", additional_info = "100 m de portée\nInstantanée\nApproximativement 2 activations par minute\n[q]Brann a une chance de sortir des chapeaux aléatoires et de les lancer sur les personnages adverses, leur infligeant des dégâts modérés et appliquant 1 affaiblissement à 3 cible.\n\n Les affaiblissements possibles comprennent une augmentation des dégâts subis de 25 %, une réduction des dégâts infligés de 25 % et une réduction de la vitesse d’attaque et d’incantation de 25 %.\n(20sec de recharge)"}
MultiLanguageSpellData['fr'][1233660] = {name = "Bout-de-rang", additional_info = "100 m de portée\nInstantanée\nApproximativement 2 activations par minute\n[q]Brann a une chance de sortir des chapeaux aléatoires et de les lancer sur les personnages adverses, leur infligeant des dégâts modérés et appliquant 2 affaiblissement à 4 cible.\n\n Les affaiblissements possibles comprennent une augmentation des dégâts subis de 30 %, une réduction des dégâts infligés de 30 % et une réduction de la vitesse d’attaque et d’incantation de 30 %.\n(20sec de recharge)"}
