MultiLanguageSpellData['fr'][1233693] = {name = "Sables de K’aresh", additional_info = "Portée illimitée\nInstantanée\n[q]Lorsque Brann utilise Outils de collecte , les sables commencent à tourbillonner autour des membres du groupe, ce qui confère 8 % au score de Coup critique, cumulable 10 fois, et ralentit les adversaires proches de 8 %.\n\n Le fait d’infliger un coup critique crée à l’emplacement de la cible un tourbillon des sables qui attire périodiquement les adversaires vers lui pendant 6 s. Cet effet ne peut se déclencher qu’une fois toutes les 45 s.\n\n Outils de collecte\nBrann utilise ses outils de collecte pour aider les personnages-joueurs à trouver de l’or, du minerai, des plantes, des poissons, du cuir et des trésors supplémentaires."}
MultiLanguageSpellData['fr'][1233694] = {name = "Sables de K’aresh", additional_info = "Portée illimitée\nInstantanée\n[q]Lorsque Brann utilise Outils de collecte , les sables commencent à tourbillonner autour des membres du groupe, ce qui confère 10 % au score de Coup critique, cumulable 10 fois, et ralentit les adversaires proches de 10 %.\n\n Le fait d’infliger un coup critique crée à l’emplacement de la cible un tourbillon des sables qui attire périodiquement les adversaires vers lui pendant 6 s. Cet effet ne peut se déclencher qu’une fois toutes les 45 s.\n\n Outils de collecte\nBrann utilise ses outils de collecte pour aider les personnages-joueurs à trouver de l’or, du minerai, des plantes, des poissons, du cuir et des trésors supplémentaires."}
MultiLanguageSpellData['fr'][1233695] = {name = "Sables de K’aresh", additional_info = "Portée illimitée\nInstantanée\n[q]Lorsque Brann utilise Outils de collecte , les sables commencent à tourbillonner autour des membres du groupe, ce qui confère 12 % au score de Coup critique, cumulable 10 fois, et ralentit les adversaires proches de 12 %.\n\n Le fait d’infliger un coup critique crée à l’emplacement de la cible un tourbillon des sables qui attire périodiquement les adversaires vers lui pendant 6 s. Cet effet ne peut se déclencher qu’une fois toutes les 45 s.\n\n Outils de collecte\nBrann utilise ses outils de collecte pour aider les personnages-joueurs à trouver de l’or, du minerai, des plantes, des poissons, du cuir et des trésors supplémentaires."}
MultiLanguageSpellData['fr'][1233699] = {name = "Nova éthérée", additional_info = "100 m de portée\nInstantanée\n[q]Lorsqu’un membre du groupe tombe sous 60 % de points de vie, un convertisseur d’énergie éthérien se matérialise, ce qui inflige des dégâts modérés aux adversaires proches et les provoque pendant 4 s. Lorsque la raillerie prend fin, le convertisseur libère une onde éthérée qui soigne les personnages alliés proches de 30 % de leurs points de vie. Cet effet ne peut être déclenché qu’une fois toutes les 2 min. Le fait de tuer des adversaires réduit le temps de recharge de cet effet de 4 s."}
MultiLanguageSpellData['fr'][1233700] = {name = "Nova éthérée", additional_info = "100 m de portée\nInstantanée\n[q]Lorsqu’un membre du groupe tombe sous 60 % de points de vie, un convertisseur d’énergie éthérien se matérialise, ce qui inflige des dégâts modérés aux adversaires proches et les provoque pendant 6 s. Lorsque la raillerie prend fin, le convertisseur libère une onde éthérée qui soigne les personnages alliés proches de 40 % de leurs points de vie. Cet effet ne peut être déclenché qu’une fois toutes les 2 min. Le fait de tuer des adversaires réduit le temps de recharge de cet effet de 6 s."}
MultiLanguageSpellData['fr'][1233701] = {name = "Nova éthérée", additional_info = "100 m de portée\nInstantanée\n[q]Lorsqu’un membre du groupe tombe sous 60 % de points de vie, un convertisseur d’énergie éthérien se matérialise, ce qui inflige des dégâts modérés aux adversaires proches et les provoque pendant 6 s. Lorsque la raillerie prend fin, le convertisseur libère une onde éthérée qui soigne les personnages alliés proches de 50 % de leurs points de vie. Cet effet ne peut être déclenché qu’une fois toutes les 2 min. Le fait de tuer des adversaires réduit le temps de recharge de cet effet de 8 s."}
