MultiLanguageSpellData['fr'][1233894] = {name = "Conduit à vent arrière", additional_info = "Portée illimitée\nInstantanée\n[q]Génère une accélération à la fin du combat, ce qui augmente votre vitesse de déplacement de 60 % pendant 10 s. Cet effet diminue sur la durée. L’utilisation d’une technique défensive à temps de recharge pendant le combat vous entoure de bourrasques de vent, ce qui applique un bouclier égal à 30 % de vos points de vie manquants et qui dure 8 s.\n(30sec de recharge)"}
MultiLanguageSpellData['fr'][1233895] = {name = "Cristal d’amplification audio", additional_info = "Portée illimitée\nInstantanée\n[q]La voix de Brann est moyennement amplifiée à l’aide de magie arcanique, ce qui permet à ses paroles d’octroyer un bonus au groupe en fonction de ce qu’il dit."}
MultiLanguageSpellData['fr'][1233896] = {name = "Égide endommagée", additional_info = "Portée illimitée\nInstantanée\n[q]Lorsque l’égide est portée, augmente et les dégâts et les soins des membres du groupe de 6 %. En combat et toutes les 10 s, Brann et vous vous soignez d’un montant égal à 10 % des dégâts subis pendant ce laps de temps.\n\n Lorsqu’un personnage-joueur meurt, l’égide lui accorde une réduction des dégâts de 2 % et un bonus aux soins reçus de 3 % à la réanimation, mais réduit les dégâts et soins produits de 2 %. Cumulable jusqu’à 3 fois."}
MultiLanguageSpellData['fr'][1233897] = {name = "Cristal de décélération temporelle", additional_info = "Portée illimitée\nInstantanée\n[q]Le fait d’infliger des dégâts à une créature élite ayant plus de 80 % ou moins de 20 % de points de vie permet à Brann de libérer les énergies du cristal, ce qui réduit la vitesse d’attaque et d’incantation de la créature de 30 % pendant 30 s. Lorsque la créature élite ciblée est tuée alors que l’affaiblissement est actif, le groupe bénéficie d’un bonus cumulable de Hâte de 4 %."}
MultiLanguageSpellData['fr'][1233898] = {name = "Appareil énigmatique", additional_info = "Portée illimitée\nInstantanée\nApproximativement 2 activations par minute\n[q]Brann a une chance d’accorder aux personnages-joueurs un bonus de 10 % aux points de vie, aux dégâts ou aux soins pendant 20 s, en fonction de son rôle au combat.\n\n Les personnages-joueurs ont une chance d’accorder à Brann un bonus de 10 % aux points de vie, aux dégâts ou aux soins pendant 20 s, en fonction du rôle choisi.\n(20sec de recharge)"}
MultiLanguageSpellData['fr'][1233899] = {name = "Convertisseur d’énergie éthérien", additional_info = "Portée illimitée\nInstantanée\n[q]Lorsqu’un membre du groupe tombe sous 60 % de points de vie, un convertisseur d’énergie éthérien se matérialise, ce qui inflige des dégâts modérés aux adversaires proches et les provoque pendant 4 s. Lorsque la raillerie prend fin, le convertisseur libère une onde éthérée qui soigne les personnages alliés proches de 30 % de leurs points de vie. Cet effet ne peut être déclenché qu’une fois toutes les 2 min. Le fait de tuer des adversaires réduit le temps de recharge de cet effet de 4 s."}
