MultiLanguageSpellData['fr'][1235934] = {name = "Marteau de la Lumière", additional_info = "100 m de portée\nInstantanée\n[q]Martèle votre adversaire avec la puissance de la Lumière, ce qui inflige ([580.645% of Attack Power]) point de dégâts du sacré, et ([290% of Attack Power]) à un maximum de 4 adversaires proches.\n\n En outre, invoque des Marteaux empyréens des cieux qui frappent 3 adversaires proches en infligeant ([46.55% of Attack Power]) point de dégâts du sacré à chaque."}
MultiLanguageSpellData['fr'][1235946] = {name = "Marque d’ire incessante", additional_info = "Instantanée\n[q]Les dégâts subis vous exaspèrent, ce qui vous fait absorber 202  point de dégâts et infliger 461  point de dégâts d’ombre par exaspération répartis entre les adversaires proches. Dégâts augmentés de 30 % par personnage adverse supplémentaire, jusqu’à un maximum de 150 %.\n\n Votre exaspération peut augmenter toutes les 15 s, cumulable jusqu’à 15 fois, mais vous vous calmez rapidement dès que vous quittez le combat.\n\nValable uniquement pour les spécialisations de tank."}
MultiLanguageSpellData['fr'][1235959] = {name = "Mage Spellslinger 11.2 Class Set 2pc", additional_info = "[q]Arcanes\n Dégâts de Déflagration des arcanes augmentés de 12 % et Déflagration des arcanes confère 1 charge d’Harmonie arcanique. Les dégâts directs des fragments ont 25 % de chances de conférer une charge d’Harmonie arcanique.\n\nFeu, Givre\n Dégâts de Javelot de glace et des glaçons augmentés de 10 % et Javelot de glace a 50 % de chances de générer 1 charge de Coup de froid. Les dégâts directs des fragments ont 15 % de chances de conférer une charge de Coup de froid."}
MultiLanguageSpellData['fr'][1235962] = {name = "Mage Sunfury 11.2 Class Set 2pc", additional_info = "[q]Arcanes, Feu, Givre\n Le bonus de dégâts des sorts de Sphère de feu-sorcier augmente de 1.0 %. Cascade de mana confère désormais 0.5 % de Hâte supplémentaire par charge."}
MultiLanguageSpellData['fr'][1235963] = {name = "Mage Frostfire 11.2 Class Set 2pc", additional_info = "[q][ Feu : Dégâts de Tempête de comètes et Détonation de givrefeu augmentés de 15 %. Dégâts d’Éclair de givrefeu augmenté de 8 %. Tempête de comètes, Détonation de givrefeu et Éclair de givrefeu applique désormais Embrasement à 75 % d’efficacité /\n\nArcanes, Givre\nDégâts de Météore et Détonation de givrefeu augmentés de 30 %. Dégâts d’Éclair de givrefeu augmentés de 10 %. Météore, Détonation de givrefeu et Éclair de givrefeu applique désormais Embrasement, ce qui inflige 25 % de dégâts supplémentaires en 9 s ]"}
MultiLanguageSpellData['fr'][1235964] = {name = "Mage Spellslinger 11.2 Class Set 4pc", additional_info = "[q]Feu\n Les dégâts des fragments sont augmentés de 8 %. Orbe arcanique a 100 % de chances de conférer une charge d’Harmonie arcanique, jusqu’à 8 fois. Lorsque Coup de froid invoque un orbe gelé, vos dégâts des sorts sont augmentés de 8 % pendant 10 s.\n\nArcanes\n Les dégâts des fragments sont augmentés de 8 %. Orbe arcanique a 100 % de chances de conférer une charge d’Harmonie arcanique, jusqu’à 8 fois. Lorsque vous atteignez 20 charge d’Harmonie arcanique, vous obtenez Intuition à 100 % d’efficacité.\n\nGivre\n Lorsque Orbe gelé inflige des dégâts à un ou plusieurs personnages adverses, il a 15 % de chances de conférer une charge de Coup de froid. Lorsque Coup de froid invoque un orbe gelé, vos dégâts des sorts sont augmentés de 8 % pendant 10 s.\n(100ms de recharge)"}
MultiLanguageSpellData['fr'][1235965] = {name = "Mage Sunfury 11.2 Class Set 4pc", additional_info = "[q]Feu, Givre\n Les sorts exceptionnels lancés par votre phénix augmentent de 0.3 s la durée de votre prochain sort Hyperthermie. Lorsque votre phénix expire, il vous renforce encore, vous octroyant Distorsion temporelle inférieure ainsi que 10 % de dégâts des sorts supplémentaires pendant 10 s.\n\nArcanes\n Les sorts exceptionnels lancés par votre phénix augmentent de 0.5 s la durée de votre prochain sort Âme des arcanes. Lorsque votre phénix expire, il vous renforce encore, vous octroyant Distorsion temporelle inférieure ainsi que 20 % de dégâts des sorts supplémentaires pendant 10 s."}
MultiLanguageSpellData['fr'][1235966] = {name = "Mage Frostfire 11.2 Class Set 4pc", additional_info = "[q]Feu\n En lançant Explosion pyrotechnique, vous avez 20 % de chances de lancer une pointe glaciaire qui inflige ([366.24% of Spell Power]) point de dégâts de givre. Les pointes glaciaires lancées de cette façon n’immobilisent pas. Par ailleurs, Pointe glaciaire bénéfice désormais également d’Enflammer.\n\nArcanes, Givre\n En lançant Pointe glaciaire, vous avez 100 % de chances de lancer une explosion pyrotechnique qui inflige ([352.5% of Spell Power]) point de dégâts de feu. Par ailleurs, Explosion pyrotechnique bénéfice désormais également d’Enflammer."}
