MultiLanguageSpellData['fr'][1236126] = {name = "Javelot de lien", additional_info = "100 m de portée\nInstantanée\n[q]Taah’bat lance des javelots arcaniques sur les personnages-joueurs ciblés, ce qui inflige 2424449 point de dégâts des arcanes aux personnages-joueurs à moins de 8 m des cibles et attache tous les personnages-joueurs touchés.\n\n Chaque lien inflige 606112 points de dégâts des arcanes toutes les 1 s, réduit la vitesse de déplacement de 50 % et augmente en intensité toutes les 5 s, jusqu’à ce que le javelot soit détruit. Cet effet est cumulable."}
MultiLanguageSpellData['fr'][1236127] = {name = "Éjection d’âme", additional_info = "30 m de portée\nInstantanée\n[q]Les âmes déliées s’éjectent rapidement dans le Vide à leur mort, ce qui inflige 2 point de dégâts des arcanes aux personnages-joueurs à moins de 30 m."}
MultiLanguageSpellData['fr'][1236128] = {name = "Charge statique", additional_info = "[q]Vos sorts et techniques ont une chance de vous conférer Charge statique, ce qui augmente votre Polyvalence de ( 17 * 20) pendant 30 s. Chaque technique et sort ultérieur réduit le bonus de Polyvalence de 5 %."}
MultiLanguageSpellData['fr'][1236129] = {name = "Courant électrique", additional_info = "[q]Vous obtenez Courant électrique en entrant en combat, ce qui augmente votre Maîtrise de 10 toutes les 2 s, jusqu’à un maximum de (12 * 10 ) au bout de 24 s. L’effet va ensuite dans le sens inverse et se répète."}
MultiLanguageSpellData['fr'][1236130] = {name = "Javelot de lien", additional_info = "100 m de portée\n3 s d'incantation\n[q]Taah’bat lance des javelots arcaniques sur les personnages-joueurs ciblés, ce qui inflige 2424449 point de dégâts des arcanes aux personnages-joueurs à moins de 8 m des cibles et attache tous les personnages-joueurs touchés.\n\n Chaque lien inflige 606112 points de dégâts des arcanes toutes les 1 s, réduit la vitesse de déplacement de 50 % et augmente en intensité toutes les 5 s, jusqu’à ce que le javelot soit détruit. Cet effet est cumulable."}
MultiLanguageSpellData['fr'][1236132] = {name = "Toucher électrique", additional_info = "[q]Vos soins ont une chance de faire des étincelles, rebondissant vers la cible ayant le moins de points de vie à moins de 40 m, ce qui lui rend 1766  points de vie."}
MultiLanguageSpellData['fr'][1236133] = {name = "Langages de Sanctuaire", additional_info = "30 m de portée\nInstantanée\n[q]Force les personnages adverses proches à s’exprimer dans la langue de Sanctuaire. Leur vitesse d’incantation est réduite de 10 % pendant jusqu’à annulation."}
MultiLanguageSpellData['fr'][1236134] = {name = "Bouclier d’énergie", additional_info = "[q]Vous avez une chance de gagner un bouclier d’énergie titanesque lorsque vous subissez des dégâts, absorbant jusqu’à 3662  point de dégâts pendant 10 s. Lorsque le bouclier prend fin, il inflige un montant de dégâts des arcanes égal à 30 % du montant d’absorption restant, répartis entre les adversaires à moins de 8 m."}
