MultiLanguageSpellData['fr'][1236145] = {name = "Plumes de feu", additional_info = "Instantanée\n[q]Feu, Givre\nLes sorts exceptionnels lancés par votre phénix augmentent de 0.3 s la durée de votre prochain sort Hyperthermie. Lorsque votre phénix expire, il vous renforce encore, vous octroyant Distorsion temporelle inférieure ainsi que 10 % de dégâts des sorts supplémentaires pendant 10 s.\n\nArcanes\nLes sorts exceptionnels lancés par votre phénix augmentent de 0.5 s la durée de votre prochain sort Âme des arcanes. Lorsque votre phénix expire, il vous renforce encore, vous octroyant Distorsion temporelle inférieure ainsi que 20 % de dégâts des sorts supplémentaires pendant 10 s."}
