MultiLanguageSpellData['fr'][1236160] = {name = "Enflammer", additional_info = "Portée illimitée\nInstantanée\n[q]Votre cible brûle et subit en 9 s un montant de dégâts supplémentaires égal à 4.0 % du total de dégâts directs de vos sorts Boule de feu, Trait de feu, Brûlure, Explosion pyrotechnique [ Météore : Météore ] [ Flammes de phénix : Flammes de phénix ] [ Tempête de cendres : Tempête de cendres ] et Choc de flammes. Si cet effet est appliqué à nouveau, les dégâts restants sont ajoutés à la nouvelle utilisation.\n\n Explosion de feu propage Enflammer à 3 adversaire proche."}
MultiLanguageSpellData['fr'][1236161] = {name = "Toucher électrique", additional_info = "[q]Les étincelles déclenchées en soignant Brann infligent un montant de dégâts égal à celui des soins à une cible adverse à moins de 40 m."}
