MultiLanguageSpellData['fr'][1236193] = {name = "Absorption de la puissance", additional_info = "20 m de portée\nCanalisée (5 s d'incantation)\n[q]Le lanceur ou la lanceuse absorbe la puissance d’un cristal proche et lance périodiquement Décharge de siphon sur des personnages-joueurs à moins de 60 m.\n\n Après la canalisation, ses dégâts sont augmentés de 50 %."}
