MultiLanguageSpellData['fr'][1236207] = {name = "Afflux astral", additional_info = "Portée illimitée\nInstantanée\n[q]Le collecteur arcanique déborde d’énergie s’il entre en contact avec une manifestation arcanique, ce qui inflige 9131730 point de dégâts des arcanes à tous les personnages-joueurs et 2670228 supplémentaire toutes les 2 s pendant 16 s."}
MultiLanguageSpellData['fr'][1236209] = {name = "Pointe glaciaire", additional_info = "{1% de la mana de base} {40 m de portée}\n2.75 s d'incantation\n[q]Invoque une énorme pointe de glace avec laquelle fusionnent tous vos glaçons actuels. Elle empale votre cible, lui inflige ([654% of Spell Power]) point de dégâts plus tous les dégâts stockés dans les glaçons et la gèle sur place pendant 4 s. Si la cible subit des dégâts, l’effet de gel peut être interrompu.\n\n Nécessite 5 glaçons pour être lancé.\n\nPassif : Javelot de glace ne lance plus de glaçons."}
MultiLanguageSpellData['fr'][1236211] = {name = "Pointe glaciaire", additional_info = "100 m de portée\nInstantanée\n[q]Invoque une énorme pointe de glace avec laquelle fusionnent tous vos glaçons actuels. Elle empale votre cible, lui inflige ([654% of Spell Power]) points de dégâts plus tous les dégâts stockés dans les glaçons, et la gèle sur place pendant 4 s. Si la cible subit des dégâts, l’effet de gel peut être interrompu.\n\n Nécessite 5 glaçons pour être lancé.\n\nPassif : Javelot de glace ne lance plus de glaçons."}
