MultiLanguageSpellData['fr'][1236254] = {name = "Death Knight Deathbringer 11.2 Class Set 4pc", additional_info = "[q]Sang, Givre, Impie\n Exterminer inflige 20 % de dégâts supplémentaires et Marque de la faucheuse peut se cumuler jusqu’à 15 fois supplémentaires. Après l’explosion de Marque de la faucheuse, vos chances de coup critique sont augmentées de 10 % pendant 8 s.\n(1sec de recharge)"}
MultiLanguageSpellData['fr'][1236256] = {name = "Enchaînement vorpal", additional_info = "10 m de portée\n2.5 s d'incantation\n[q]Le lanceur ou la lanceuse fauche la zone vers l’avant, ce qui inflige des dégâts d’ombre et applique un bouclier d’absorption de soins sur les personnages-joueurs touchés."}
MultiLanguageSpellData['fr'][1236259] = {name = "Death Knight San'layn 11.2 Class Set 2pc", additional_info = "[q]Impie\n Traitement de douleur augmente la durée de la maladie d’encore 3.0 s sur votre cible principale. Essence de la reine de sang augmente également votre Maîtrise de 0.5 % par charge.\n\nSang, Givre\n Traitement de douleur augmente la durée de la maladie d’encore 4.0 s sur votre cible principale. Essence de la reine de sang augmente également votre Maîtrise de 0.5 % par charge."}
MultiLanguageSpellData['fr'][1236260] = {name = "Death Knight San'layn 11.2 Class Set 4pc", additional_info = "[q]Impie\n Traitement de douleur inflige 30 % de dégâts supplémentaires et Frappe vampirique augmente les dégâts de votre goule de 20 % pendant 8 s. Cet effet peut être appliqué plusieurs fois simultanément.\n\nSang, Givre\n Traitement de douleur inflige 50 % de dégâts supplémentaires et Frappe vampirique augmente les dégâts de vos armes runiques dansantes de 20 % pendant 8 s. Cet effet peut être appliqué plusieurs fois simultanément."}
MultiLanguageSpellData['fr'][1236262] = {name = "Serpent sage de Shaohao", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie cette monture.\n[q]\"Les leçons tirées par Shaohao de la vie et dans la mort, ainsi que la passion qu’il entretenait pour son pays, ont été réunies dans ce serpent éthérien, reflet de la sagesse de l’empereur.\"\nPromotion :\nMists of Pandaria Classic"}
