MultiLanguageSpellData['fr'][1236330] = {name = "Druid Druid of the Claw 11.2 Class Set 4pc", additional_info = "[q]Ravage a 40 % de chances de se lancer une seconde fois sur la cible au bout de 4 s [ Farouche : à 100 % de sa puissance de base /\n\nÉquilibre, Gardien, Restauration\nà 60 % d’efficacité ]"}
MultiLanguageSpellData['fr'][1236331] = {name = "Druid Druid of the Claw 11.2 Class Set 2pc", additional_info = "[q]Ravage augmente votre Hâte de 10 %, vos chances de coup critique de 10 % et les dégâts de vos saignements de 30 % pendant 5 s.\n(100ms de recharge)"}
MultiLanguageSpellData['fr'][1236332] = {name = "Druid Elune's Chosen 11.2 Class Set 2pc", additional_info = "[q]Équilibre\n Les dégâts de Feu stellaire sont augmentés de 25 %. Lorsque vous gagnez de la puissance astrale avec Feu stellaire, vous avez 50 % de chances de lancer Éruption stellaire sur une cible à 50 % d’efficacité.\n\nFarouche, Gardien, Restauration\n Les dégâts de Rosser sont augmentés de 20 %. Lorsque vous lancez Rosser, vous avez 40 % de chances de lancer Éruption stellaire sur une cible à 160 % d’efficacité.\n(100ms de recharge)"}
MultiLanguageSpellData['fr'][1236333] = {name = "Druid Elune's Chosen 11.2 Class Set 4pc", additional_info = "[q]Équilibre\n À l’impact, chaque Éruption stellaire déclenchée par Feu stellaire se propage à un maximum de 3 cibles supplémentaires à 80 % d’efficacité et octroie une charge d’Accumulation de clair de lune. En lançant Fureur d’Élune ou Pleine lune, vous consommez Accumulation de clair de lune et augmentez vos dégâts de 4 % par charge pendant 12 s.\n\nFarouche, Gardien, Restauration\n À l’impact, chaque Éruption stellaire déclenchée par Rosser se propage à un maximum de 3 cibles supplémentaires à 20 % d’efficacité et octroie une charge d’Accumulation de clair de lune. En lançant Rayon lunaire, vous consommez Accumulation de clair de lune et augmentez vos dégâts de 4 % par charge pendant 12 s."}
MultiLanguageSpellData['fr'][1236334] = {name = "Druid Keeper of the Grove 11.2 Class Set 2pc", additional_info = "[q]Équilibre, Farouche, Gardien\n En lançant Alignement céleste, vous faites appel à une dryade pendant 10 s. Elle lance Éruption stellaire à 360 % d’efficacité et Météores à 800 % d’efficacité.\n\nRestauration\n En lançant Incarnation : Arbre de vie ou Convoquer les esprits, vous faites appel à une dryade pendant 5 s. Elle lance Tranquillité à 50 % d’efficacité, ainsi que Rétablissement à 200 % d’efficacité instantanément sur le personnage allié ayant le moins de points de vie."}
MultiLanguageSpellData['fr'][1236336] = {name = "Druid Keeper of the Grove 11.2 Class Set 4pc", additional_info = "[q]Restauration\n Lorsque votre dryade disparaît, vos 2 prochaines utilisations de Prompt rétablissement soignent pour 5 % des soins prodigués tant qu’elle était active. 25 % des soins prodigués sont propagés aux personnages alliés proches (effet réduit au - delà de 5 cibles).\n\nÉquilibre, Farouche, Gardien\n Lorsque votre dryade disparaît, vos 2 prochaines utilisations d’Éruption stellaire infligent des dégâts pour 2 % des dégâts infligés tant qu’elle était active. 10 % des dégâts infligés sont propagés aux adversaires proches (effet réduit au - delà de 5 cibles)."}
MultiLanguageSpellData['fr'][1236337] = {name = "Druid Wildstalker 11.2 Class Set 2pc", additional_info = "[q]Équilibre, Gardien, Restauration\n Augmente la vitesse de pousse de Floraison symbiotique de 30 %. En lançant Rétablissement sous l’effet d’Idées claires, vous permettez à Floraison symbiotique d’atteindre jusqu’à un maximum de 2 personnages alliés proches valides.\n\nFarouche\n Augmente la vitesse de pousse de Lianes sanguinaires de 40 %. Fureur du tigre permet à Lianes sanguinaires d’atteindre jusqu’à un maximum de 3 adversaires proches valides."}
MultiLanguageSpellData['fr'][1236338] = {name = "Druid Wildstalker 11.2 Class Set 4pc", additional_info = "[q]Équilibre, Gardien, Restauration\n Floraison symbiotique a 20 % de chances de déclencher Croissance effrénée toutes les 2 s à 80 % d’efficacité. Chaque charge de Floraison symbiotique sur un personnage allié augmente les soins prodigués par Croissance effrénée de 30 %.\n\nFarouche\n Lianes sanguinaires a 20 % de chances de déclencher Croissance effrénée toutes les 2 s à 100 % d’efficacité. Chaque charge de Lianes sanguinaires sur un personnage ennemi augmente les dégâts infligés par Croissance effrénée de 40 %."}
MultiLanguageSpellData['fr'][1236342] = {name = "Se préparer à frapper", additional_info = "Instantanée\n[q]Ravage a 40 % de chances de se lancer une seconde fois sur la cible au bout de 4 s [ Farouche : à 100 % de sa puissance de base /\n\nÉquilibre, Gardien, Restauration\nà 60 % d’efficacité ]"}
