MultiLanguageSpellData['fr'][1236348] = {name = "Entaille chargée", additional_info = "100 m de portée\n{4 s d'incantation} {3 s de recharge}\n[q]Zo’phex charge ses épées et libère une taillade colossale, infligeant 15758921 point de dégâts physiques à tous les personnages adverses en face de lui."}
MultiLanguageSpellData['fr'][1236350] = {name = "Void Power Shard Released Visuals - COSMETIC", additional_info = nil}
MultiLanguageSpellData['fr'][1236354] = {name = "Siphon d’âme", additional_info = "40 m de portée\n{2 s d'incantation} {5 s de recharge}\n[q]Le lanceur ou la lanceuse ralentit sa cible et lui draine 622547 point de vie en 8 s, tout en récupérant un montant de points de vie égal au double du montant drainé."}
MultiLanguageSpellData['fr'][1236355] = {name = "Death Knight Rider of the Apocalypse 11.2 Class Set 2pc", additional_info = "[q][ Givre : Pilier de givre invoque désormais Trollemort pendant 10 s. Fureur gelée de Trollemort inflige 20 % de dégâts supplémentaires et Anéantissement inflige 35 % de dégâts supplémentaires /\n\nSang, Impie\nApocalypse invoque désormais Blanchetête pendant 10 s. Non-mort de Blanchetête inflige 20 % de dégâts supplémentaires et infecte 1 cible supplémentaire en se propageant. Par ailleurs, son Voile mortel inflige 35 % de dégâts supplémentaires ]"}
MultiLanguageSpellData['fr'][1236356] = {name = "Death Knight Rider of the Apocalypse 11.2 Class Set 4pc", additional_info = "[q][ Givre : En lançant Anéantissement ou Faux de givre, vous ordonnez à Trollemort de lancer la même technique à 100 % d’efficacité. Votre Anéantissement inflige 20 % de dégâts supplémentaires aux cibles affectées par Fureur gelée de Trollemort /\n\nSang, Impie\nEn lançant Voile mortel ou Épidémie, vous ordonnez à Blanchetête de lancer la même technique à 125 % d’efficacité. Votre Voile mortel inflige 40 % de dégâts supplémentaires aux cibles affectées par Non-mort de Blanchetête ](500ms de recharge)"}
MultiLanguageSpellData['fr'][1236358] = {name = "Demon Hunter Aldrachi Reaver 11.2 Class Set 2pc", additional_info = "[q]Les dégâts de Glaive de saccageur sont augmentés de 50 % et tous les autres dégâts uniquement physiques sont augmentés de 25 %."}
MultiLanguageSpellData['fr'][1236360] = {name = "Demon Hunter Aldrachi Reaver 11.2 Class Set 4pc", additional_info = "[q]Dévastation\n Fureur des Aldrachi renforce davantage Danse des lames si elle est lancée après Frappe du chaos, portant la puissance des taillades à 12.\n\n Marque du saccageur peut désormais cumuler jusqu’à un maximum de 2 charges et renforce davantage Frappe du chaos si elle est lancée après Danse des lames, et applique une charge supplémentaire pour 100 % de la durée normale.\n\nVengeance\n Fureur des Aldrachi renforce davantage Division de l’âme si elle est lancée après Entaille, portant la puissance des taillades à 12.\n\n Marque du saccageur peut désormais cumuler jusqu’à un maximum de 2 charges et renforce davantage Entaille si elle est lancée après Division de l’âme, et applique une charge supplémentaire pour 100 % de la durée normale."}
MultiLanguageSpellData['fr'][1236361] = {name = "Demon Hunter Fel-Scarred 11.2 Class Set 2pc", additional_info = "[q]Aura d’immolation inflige 30 % de dégâts supplémentaires. Tant qu’elle est active, l’aura augmente les dégâts de [ Vengeance : Division de l’âme /\n\nDévastation\nFrappe du chaos ] de 20 %."}
MultiLanguageSpellData['fr'][1236362] = {name = "Demon Hunter Fel-Scarred 11.2 Class Set 4pc", additional_info = "[q]Dévastation\n Désormais, lorsque vous adoptez votre forme de démon, vous déclenchez immédiatement Afflux démoniaque et obtenez un fragment d’âme de démon octroyant 20 % de dégâts supplémentaires pendant 10 s.\n\nVengeance\n Désormais, lorsque vous adoptez votre forme de démon, vous déclenchez immédiatement Afflux démoniaque et obtenez un fragment d’âme de démon octroyant 20 % de dégâts supplémentaires pendant 15 s.\n(100ms de recharge)"}
MultiLanguageSpellData['fr'][1236364] = {name = "Evoker Flameshaper 11.2 Class Set 2pc", additional_info = "[q]Engloutir ravive votre Flamme intérieure, ce qui augmente vos dégâts et soins sur la durée de 25 % et vos chances d’obtenir Explosion d’essence de 50 % pendant 12 s. Cumulable jusqu’à 2 fois."}
MultiLanguageSpellData['fr'][1236365] = {name = "Evoker Flameshaper 11.2 Class Set 4pc", additional_info = "[q]Lorsque vous consommez Explosion d’essence pendant Flamme intérieure, vous lancez une bombe d’essence sur votre cible, [ Dévastation : infligeant ([371% of Spell Power]) point de dégâts des arcanes aux adversaires proches /\n\nPréservation, Augmentation\nrendant ([250% of Spell Power]) point de vie aux personnages alliés proches ] Effet réduit au-delà de 5 cibles."}
MultiLanguageSpellData['fr'][1236366] = {name = "Evoker Scalecommander 11.2 Class Set 2pc", additional_info = "[q]Augmentation ( Augmentation d’évocateur )\n Lorsque vous volez pendant Souffle profond et pendant 20 s après, vous prenez les commandes d’un escadron de 2 personnages dracthyrs qui lancent Désintégration et Bûcher contre vos cibles.\n\n Dévastation, Préservation\n Lorsque vous volez pendant [ Souffle des présages / Souffle profond] et pendant 10 s après, vous prenez les commandes d’un escadron de 2 personnages dracthyrs qui lancent Désintégration et Bûcher contre vos cibles."}
MultiLanguageSpellData['fr'][1236367] = {name = "Evoker Scalecommander 11.2 Class Set 4pc", additional_info = "[q]Augmentation ( Augmentation d’évocateur )\n Tant que votre escadron est actif, Éruption de masse frappe jusqu’à 2 cible supplémentaire. Par ailleurs, votre escadron vous aide pendant 10 s supplémentaires.\n\n Dévastation, Préservation\n Tant que votre escadron est actif, [ Dévastation : Désintégration de masse /\n\nPréservation, Augmentation\nÉruption de masse ] frappe jusqu’à 2 cible supplémentaire. Par ailleurs, votre escadron vous aide pendant 5 s supplémentaires."}
MultiLanguageSpellData['fr'][1236368] = {name = "Evoker Chronowarden 11.2 Class Set 2pc", additional_info = "[q]Le temps de recharge de Retour de bâton est réduit de 60 s."}
MultiLanguageSpellData['fr'][1236369] = {name = "Evoker Chronowarden 11.2 Class Set 4pc", additional_info = "[q]Temporal Burst causes Chrono Flames to strike 2 additional target and repeat 15% additional damage or healing, up to a maximum of [(Puissance des sorts * 4.5) * (1 + Versatilité)], and increases Essence ability damage and healing by 30%."}
MultiLanguageSpellData['fr'][1236370] = {name = "Hunter Dark Ranger 11.2 Class Set 2pc", additional_info = "[q]Précision, Survie\n Les dégâts des tirs de Flèche noire sont augmentés de 10 % et ceux de Poudre sinistre de 20 %. Le temps de recharge de Précision est réduit de 30 s.\n\nMaîtrise des bêtes\n Les dégâts des tirs de Flèche noire sont augmentés de 10 % et ceux de Poudre sinistre de 20 %. Le temps de recharge d’Appel de la Nature est réduit de 60 s."}
MultiLanguageSpellData['fr'][1236371] = {name = "Hunter Dark Ranger 11.2 Class Set 4pc", additional_info = "[q]Les dégâts des flèches noires de Feu cinglant sont augmentés de 50 %. En consommant Coup définitif, vous avez [ Maîtrise des bêtes : 50 /\n\nPrécision, Survie\n50 ] % de chances que tous les barrages de flèches noires durant votre prochain Feu cinglant tirent 1 flèche noire supplémentaire."}
MultiLanguageSpellData['fr'][1236372] = {name = "Hunter Pack Leader 11.2 Class Set 2pc", additional_info = "[q]Les dégâts des familiers sont augmentés de [ Maîtrise des bêtes : 5 /\n\nPrécision, Survie\n15 ] % et ceux des bêtes de 15 %. En invoquant une bête, vous obtenez 6 % de Hâte, de Maîtrise ou de chances de coup critique en fonction de celle invoquée pendant 8 s."}
MultiLanguageSpellData['fr'][1236373] = {name = "Hunter Pack Leader 11.2 Class Set 4pc", additional_info = "[q]Le fait d’invoquer une bête sous l’effet de Première ligne provoque une ruée des animaux sauvages proches, qui chargent votre cible et infligent [([300% of Attack Power]) * 9] point de dégâts physiques à un maximum de 8 adversaires en 7 s."}
MultiLanguageSpellData['fr'][1236374] = {name = "Hunter Sentinel 11.2 Class Set 2pc", additional_info = "[q]Maîtrise des bêtes, Survie\n Dégâts de Bombe de feu de brousse augmentés de 10 %. Lorsque Tempête lunaire se dissipe, vous obtenez Don d’Élune, qui permet à 2 prochaines utilisations de Bombe de feu de brousse d’infliger des dégâts des arcanes et de bénéficier d’un bonus initial de 150 % de dégâts.\n\nPrécision\n Dégâts de Tir rapide augmentés de 25 %. Lorsque Tempête lunaire se dissipe, vous obtenez Don d’Élune, qui permet à 2 prochaines utilisations de Visée d’infliger des dégâts des arcanes et de bénéficier d’un bonus de 10 % de dégâts."}
MultiLanguageSpellData['fr'][1236375] = {name = "Hunter Sentinel 11.2 Class Set 4pc", additional_info = "[q]Précision ( Chasseur Précision )\n Les dégâts de Sentinelle sont augmentés de 18 %.Don d’Élune est désormais actif pendant toute la durée de Tempête lunaire à 100 % d’efficacité.\n\n Maîtrise des bêtes, Survie\n Les dégâts de Sentinelle sont augmentés de 20 %.Don d’Élune est désormais actif pendant toute la durée de Tempête lunaire à 100 % d’efficacité."}
MultiLanguageSpellData['fr'][1236376] = {name = "Lacis de l’âme", additional_info = nil}
MultiLanguageSpellData['fr'][1236377] = {name = "Monk Master of Harmony 11.2 Class Set 2pc", additional_info = "[q]Maître brasseur\n Lorsque vous obtenez de la vitalité, votre prochaine Paume du tigre a davantage de chances de déclencher Afflux harmonique, infligeant [180 * ([400% of Spell Power]) / 100] point de dégâts de nature réparti entre votre cible et les autres adversaires proches et rendant [20 * ([500% of Spell Power]) / 100] point de vie à un maximum de 5 personnages alliés blessés.\n\nMarche-vent, Tisse-brume\n Lorsque vous obtenez de la vitalité, votre prochaine Paume du tigre a davantage de chances de déclencher Afflux harmonique, infligeant [20 * ([400% of Spell Power]) / 100] point de dégâts de nature réparti entre votre cible et les autres adversaires proches et rendant [90 * ([500% of Spell Power]) / 100] point de vie à un maximum de 5 personnages alliés blessés."}
MultiLanguageSpellData['fr'][1236378] = {name = "Monk Master of Harmony 11.2 Class Set 4pc", additional_info = "[q]Marche-vent, Tisse-brume\n Lorsque vous lancez Thé de concentration foudroyante , 2 utilisation suivante de Paume du tigre déclenche Afflux harmonique.\n\nMaître brasseur\n Lorsque vous lancez , 2 utilisation suivante de Paume du tigre déclenche Afflux harmonique."}
MultiLanguageSpellData['fr'][1236379] = {name = "Monk Shado-Pan 11.2 Class Set 2pc", additional_info = "[q]Déluge de coups inflige 20 % de dégâts supplémentaires. En activant [ Maître brasseur : Armes de l’Ordre /\n\nMarche-vent, Tisse-brume\nTempête, Terre et Feu ] vous obtenez 10 charges de Déluge de coups, qui se déclenchent lors de votre prochaine attaque à 70 % d’efficacité."}
MultiLanguageSpellData['fr'][1236380] = {name = "Monk Shado-Pan 11.2 Class Set 4pc", additional_info = "[q]Marche-vent ( Moine / moniale Marche - vent )\n La génération de charge de déluge est augmentée de 50 % et Déluge de coups se déclenche tous les 120 points d’énergie dépensés pendant Tempête, Terre et Feu.\n\n Maître brasseur, Tisse-brume\n La génération de charge de déluge est augmentée de 50 % et Déluge de coups se déclenche tous les 150 points d’énergie dépensés pendant [ Marche-vent : Tempête, Terre et Feu /\n\nMaître brasseur, Tisse-brume\nArmes de l’Ordre ]"}
MultiLanguageSpellData['fr'][1236381] = {name = "Monk Conduit of the Celestials 11.2 Class Set 2pc", additional_info = "[q]Marche-vent ( Moine / moniale Marche - vent )\n Cœur du Serpent de jade se déclenche également pendant 4 s à 100 % d’efficacité après lancement de Vents tranchants.\n\n Maître brasseur, Tisse-brume\n Cœur du Serpent de jade se déclenche également pendant 8 s à 100 % d’efficacité après lancement de [ Marche-vent : Vents tranchants /\n\nMaître brasseur, Tisse-brume\nThé de concentration foudroyante ](1sec de recharge)"}
MultiLanguageSpellData['fr'][1236382] = {name = "Monk Conduit of the Celestials 11.2 Class Set 4pc", additional_info = "[q]Cœur du Serpent de jade augmente votre Hâte de 10 % tant qu’il est actif et pendant 4 s après expiration."}
MultiLanguageSpellData['fr'][1236383] = {name = "Paladin Herald of the Sun 11.2 Class Set 2pc", additional_info = "[q]Sacré ( Paladin Sacré )\n Les soins et les dégâts d’Aubastre sont augmentés de 60 % et vous obtenez Courroux solaire lorsque Courroux vengeur se dissipe, ce qui permet à l’effet d’Avatar solaire de durer 10[10][10] s supplémentaire.\n\n Protection, Vindicte\n Les soins et les dégâts d’Aubastre sont augmentés de 30 % et vous obtenez Courroux solaire lorsque Courroux vengeur se dissipe, ce qui permet à l’effet d’Avatar solaire de durer [ Croisé vengeur : 5 ] [ Croisade : 20 ] [ Sacré : 10 / [10][10] s supplémentaire."}
MultiLanguageSpellData['fr'][1236384] = {name = "Paladin Herald of the Sun 11.2 Class Set 4pc", additional_info = "[q]Sacré ( Paladin Sacré )\n Courroux solaire augmente l’efficacité de vos techniques consommant de la puissance sacrée de 30 % et vous octroie 2[2][2] fois Aubastre.\n\n Protection, Vindicte\n Courroux solaire augmente l’efficacité de vos techniques consommant de la puissance sacrée de 15 % et vous octroie [ Croisé vengeur : 1 ] [ Croisade : 4 ] [ Sacré : 2 / [2][2] fois Aubastre."}
MultiLanguageSpellData['fr'][1236385] = {name = "Mitraille d’âme", additional_info = nil}
MultiLanguageSpellData['fr'][1236389] = {name = "Paladin Lightsmith 11.2 Class Set 2pc", additional_info = "[q]Protection\n Les dégâts de Marteau et enclume sont augmentés de 15 % et la technique peut également être activée par à 40 % d’efficacité.\n\nVindicte\n Les soins de Marteau et enclume sont augmentés de 15 % et la technique peut également être activée par Frappe du croisé à 40 % d’efficacité.\n\nSacré\n Les soins de Marteau et enclume sont augmentés de 15 % et la technique peut également être activée par Frappe du croisé à 75 % d’efficacité.\n(750ms de recharge)"}
MultiLanguageSpellData['fr'][1236390] = {name = "Paladin Lightsmith 11.2 Class Set 4pc", additional_info = "[q]Marteau et enclume octroie également une charge de Chef-d’œuvre, ce qui permet à votre prochain Armement sacré de lancer une version plus faible sur un personnage allié proche par charge accumulée."}
MultiLanguageSpellData['fr'][1236391] = {name = "Paladin Templar 11.2 Class Set 2pc", additional_info = "[q]Marteau empyréen inflige 20 % de dégâts critiques supplémentaires et ses coups critiques ont 50 % de chances d’octroyer une charge supplémentaire de Délivrance de la Lumière.\n(Chance d'occurence :50%)"}
MultiLanguageSpellData['fr'][1236392] = {name = "Paladin Templar 11.2 Class Set 4pc", additional_info = "[q]Vindicte\n Marteau de la Lumière inflige 35 % de dégâts supplémentaires à la cible principale, touche 3 cibles secondaires supplémentaires et peut désormais être lancé 1 fois supplémentaire après Traînée de cendres.\n\nSacré, Protection\n Marteau de la Lumière inflige 35 % de dégâts supplémentaires à la cible principale, touche 3 cibles secondaires supplémentaires et peut désormais être lancé 1 fois supplémentaire après Œil de Tyr."}
MultiLanguageSpellData['fr'][1236394] = {name = "Priest Oracle 11.2 Class Set 2pc", additional_info = "[q][ Discipline : Le premier projectile de chaque lancer de Pénitence bénéficie d’un bonus de 200 % de dégâts ou de soins /\n\nSacré, Ombre\nPrière de guérison soigne votre cible de ([1400% of Spell Power]) point de vie. ]"}
MultiLanguageSpellData['fr'][1236395] = {name = "Priest Oracle 11.2 Class Set 4pc", additional_info = "[q]Le lancement de Prémonition de piété ou Prémonition de soulagement octroie 2 charge de Prémonition de perspicacité à 100 % d’efficacité. Lorsque vous dépensez une charge de Prémonition de perspicacité, vous augmentez votre Hâte de 1.0 % pendant 10 s. Cet effet peut être appliqué plusieurs fois simultanément."}
MultiLanguageSpellData['fr'][1236396] = {name = "Priest Voidweaver 11.2 Class Set 2pc", additional_info = "[q]Discipline\n Les dégâts de Trait de Vide et Pénitence sont augmentés de 30 %. Le temps d’incantation de Trait de Vide est réduit de 20 %.\n\nSacré\n Les dégâts de Trait de Vide sont augmentés de 30 %. Le temps d’incantation de Trait de Vide est réduit de 20 %.\n\nOmbre\n Les dégâts de Trait de Vide sont augmentés de 30 %. Le temps d’incantation de Trait de Vide est réduit de 20 %. Le temps de recharge de Trait de Vide est réduit de 50 %."}
MultiLanguageSpellData['fr'][1236397] = {name = "Priest Voidweaver 11.2 Class Set 4pc", additional_info = "[q]Discipline\n Trait de Vide permet désormais également à Faille entropique de s’étendre et Effondrement du Vide augmente les dégâts de Faille entropique de 10 % supplémentaires. La prochaine fois que vous utilisez Attaque mentale, ses dégâts sont augmentés de 200 %, en fonction de la taille de Faille entropique lorsqu’elle disparaît.\n\nSacré, Ombre\n Trait de Vide permet désormais également à Faille entropique de s’étendre et Effondrement du Vide augmente les dégâts de Faille entropique de 10 % supplémentaires. La prochaine fois que vous utilisez Torrent du Vide, ses dégâts sont augmentés de 200 %, en fonction de la taille de Faille entropique lorsqu’elle disparaît."}
MultiLanguageSpellData['fr'][1236398] = {name = "Priest Archon 11.2 Class Set 2pc", additional_info = "[q]Ombre\n Les halos génèrent 10 point d’insanité supplémentaire en 5 s. Énergie résonante augmente également les dégâts de votre Peste dévorante de 5.0 %.\n\nDiscipline, Sacré\n Les halos réduisent le temps de recharge de vos Mot sacré : Sérénité et Mot sacré : Sanctification de 5 s. Énergie résonante augmente également les soins de vos Mots sacrés de 5.0 %."}
MultiLanguageSpellData['fr'][1236399] = {name = "Priest Archon 11.2 Class Set 4pc", additional_info = "[q]Tant que Surtension est active, toutes les 2 utilisations de [ Sacré : Mot sacré : Sérénité ou Mot sacré : Sanctification /\n\nDiscipline, Ombre\nPeste dévorante ] vous ajoutez un nouveau halo à 100 % d’efficacité, jusqu’à un maximum de 2 fois."}
MultiLanguageSpellData['fr'][1236400] = {name = "Rogue Deathstalker 11.2 Class Set 2pc", additional_info = "[q]Assassinat\n Kriss augmente l’efficacité de tous les effets de dégâts et bonus de dégâts de Nécrotraqueur de 60 % tant que l’effet est actif.\n\nHors-la-loi, Finesse\n Symboles de mort augmente l’efficacité de tous les effets de dégâts et bonus de dégâts de Nécrotraqueur de 40 % tant que l’effet est actif."}
MultiLanguageSpellData['fr'][1236401] = {name = "Rogue Deathstalker 11.2 Class Set 4pc", additional_info = "[q][ Assassinat : Kriss /\n\nHors-la-loi, Finesse\nSymboles de mort ] dure 3 s de plus et consomme un cumul de votre Marque de nécrotraqueur en cours à l’activation."}
MultiLanguageSpellData['fr'][1236402] = {name = "Rogue Fatebound 11.2 Class Set 2pc", additional_info = "[q]Hors-la-loi\n Frappe fantomatique inflige 50 % de dégâts supplémentaires et sa durée est augmentée de 4 s.\n\n Cas limite jette désormais une pièce prédestinée supplémentaire, dont l’effet est déclenché à l’activation de Frappe fantomatique.\n\nAssassinat, Finesse\n Plaie des rois inflige 10 % de dégâts supplémentaires et sa durée est augmentée de 4 s.\n\n Cas limite jette désormais une pièce prédestinée supplémentaire, dont l’effet est déclenché à l’activation de Plaie des rois."}
MultiLanguageSpellData['fr'][1236403] = {name = "Rogue Fatebound 11.2 Class Set 4pc", additional_info = "[q]Assassinat, Finesse\n Lorsque vous possédez une pièce prédestinée positive, vous réduisez le temps de recharge de Marque létale de 30.0 s et celui de Plaie des rois de 15.0 s.\n\nHors-la-loi\n Lorsque vous possédez une pièce prédestinée positive, vous réduisez le temps de recharge de Poussée d’adrénaline de 30.0 s et celui de Frappe fantomatique de 15.0 s."}
MultiLanguageSpellData['fr'][1236404] = {name = "Rogue Trickster 11.2 Class Set 2pc", additional_info = "[q]Lame invisible inflige 35 % de dégâts supplémentaires et a 35 % de chances de frapper deux fois."}
MultiLanguageSpellData['fr'][1236405] = {name = "Rogue Trickster 11.2 Class Set 4pc", additional_info = "[q]Achèvement peut désormais être activé une seconde fois dans les 5 s qui suivent, infligeant 150 % des dégâts normaux."}
MultiLanguageSpellData['fr'][1236406] = {name = "Shaman Farseer 11.2 Class Set 2pc", additional_info = "[q]Rapidité ancestrale invoque un personnage d’ancêtre renforcé pendant 15 s. Il inflige 10 % de dégâts et de soins supplémentaires."}
MultiLanguageSpellData['fr'][1236407] = {name = "Shaman Farseer 11.2 Class Set 4pc", additional_info = "[q]Rapidité ancestrale augmente les dégâts et les soins de vos sorts de 25 %, réduit leur coût en mana de 25 % et augmente la vitesse de recharge d’Explosion de lave [ Restauration : et de Remous ] de 50 % pendant 8 s."}
MultiLanguageSpellData['fr'][1236408] = {name = "Shaman Stormbringer 11.2 Class Set 2pc", additional_info = "[q]Amélioration, Restauration\n Ascendance a 100 % de chances d’octroyer une charge de Tempête. Toutes les 8 utilisations de Tempêtes de l’Éveil, Ascendance se déclenche pendant 6.0 s.\n\nÉlémentaire\n Ascendance a 100 % de chances d’octroyer une charge de Tempête. Toutes les 9 utilisations de Tempêtes de l’Éveil, Ascendance se déclenche pendant 6.0 s.\n(100ms de recharge)"}
MultiLanguageSpellData['fr'][1236409] = {name = "Shaman Stormbringer 11.2 Class Set 4pc", additional_info = "[q]Élémentaire, Restauration\n Dégâts de nature augmentés de 3.0 % et Sublimation renforce vos 2 prochaines utilisations de Tempête, lui permettant de déclencher un orage infligeant ([960% of Spell Power]) point de dégâts de nature à la cible principale ainsi que des dégâts réduits aux adversaires proches au bout de 1.5 s.\n\nAmélioration\n Dégâts de nature augmentés de 5.0 % et Sublimation renforce vos 2 prochaines utilisations de Tempête, lui permettant de déclencher un orage infligeant ([400% of Attack Power]) point de dégâts de nature à la cible principale ainsi que des dégâts réduits aux adversaires proches au bout de 1.5 s.\n(100ms de recharge)"}
MultiLanguageSpellData['fr'][1236410] = {name = "Shaman Totemic 11.2 Class Set 2pc", additional_info = "[q]Amélioration\n Après que vous avez consommé tous les granules d’Éléments tourbillonnants, votre totem déferlant lance Tempête primordiale à 200 % d’efficacité à son emplacement.\n\nÉlémentaire, Restauration\n Après que vous avez consommé tous les granules d’Éléments tourbillonnants, vous lancez Giboulée à 200 % d’efficacité à l’emplacement de votre totem déferlant."}
MultiLanguageSpellData['fr'][1236411] = {name = "Shaman Totemic 11.2 Class Set 4pc", additional_info = "[q]Élémentaire, Restauration\n Après lancement de Giboulée, votre prochain sort Salve de guérison, Vague de soins ou Afflux de soins est lancé une deuxième fois à 150 % d’efficacité.\n\nAmélioration\n Après lancement de Tempête primordiale, votre prochain sort Fouet de lave ou Nova de feu est lancé une deuxième fois à 150 % d’efficacité.\n(500ms de recharge)"}
MultiLanguageSpellData['fr'][1236413] = {name = "Warlock Hellcaller 11.2 Class Set 2pc", additional_info = "[q]Marque de Xavius augmente les dégâts d’Âme noircie d’encore [ Affliction : 6 /\n\nDémonologie, Destruction\n3 ] % par charge. Malveillance augmente de 2 le nombre de charges de Flétrissement."}
MultiLanguageSpellData['fr'][1236414] = {name = "Warlock Hellcaller 11.2 Class Set 4pc", additional_info = "[q]Affliction\n Le lancement de Malveillance octroie 2 charges de Crescendo torturé, évite à Âme noircie de consommer des charges et inflige ses dégâts 25 % plus rapidement pendant 8 s.\n\nDémonologie, Destruction\n Le lancement de Malveillance octroie 2 charges de Retour de flamme, évite à Âme noircie de consommer des charges et inflige ses dégâts 15 % plus rapidement pendant 8 s."}
MultiLanguageSpellData['fr'][1236415] = {name = "Warlock Soul Harvester 11.2 Class Set 2pc", additional_info = "[q]Ombre de la mort projette votre âme démoniaque sur votre cible actuelle pendant 9 s, infligeant ([279.306% of Spell Power]) point de dégâts d’ombre et ([186.209% of Spell Power]) aux adversaires à moins de 10 m à chaque coup."}
MultiLanguageSpellData['fr'][1236416] = {name = "Warlock Soul Harvester 11.2 Class Set 4pc", additional_info = "[q]Les dégâts d’Âme démoniaque sont augmentés de 45 % et ceux de Récolte pernicieuse de 45 %. Votre âme démoniaque génère 1 fragment d’âme toutes les 3 s lorsque vous attaquez des adversaires."}
MultiLanguageSpellData['fr'][1236417] = {name = "Warlock Diabolist 11.2 Class Set 2pc", additional_info = "[q][ Démonologie : Main de Gul’dan lancée à pleine puissance /\n\nAffliction, Destruction\nLe lancement de Trait du chaos, Pluie de feu ou Brûlure de l’ombre ] invoque un oculus démoniaque, jusqu’à un maximum de 3. La consommation d’Art démoniaque projette vos oculus démoniaques sur votre cible actuelle. Ils explosent en infligeant ([914.206% of Spell Power]) points de dégâts de feu et ([609.404% of Spell Power]) aux adversaires à moins de 10 m."}
MultiLanguageSpellData['fr'][1236418] = {name = "Warlock Diabolist 11.2 Class Set 4pc", additional_info = "[q]L’oculus démoniaque analyse le combat tant qu’il est actif et vous octroie des informations en explosant, ce qui augmente votre Intelligence de 2 % pendant 10 s."}
MultiLanguageSpellData['fr'][1236419] = {name = "Warrior Colossus 11.2 Class Set 2pc", additional_info = "[q]Les dégâts de Démolissage sont augmentés de 20 % et les dégâts critiques de vos techniques sont augmentés d’un maximum de 20 % contre les cibles que vous avez touchées avec Démolissage pendant 10 s, en fonction du nombre de charges de Puissance colossale consommées."}
MultiLanguageSpellData['fr'][1236420] = {name = "Warrior Colossus 11.2 Class Set 4pc", additional_info = "[q]Armes\n Démolissage augmente de 100 % vos chances de coup critique pour 1 utilisation suivante de Frappe mortelle. Les coups critiques de Frappe mortelle augmentent les dégâts de Pourfendre et Blessures profondes de 80 % pendant 8 s.\n\nFureur, Protection\n Démolissage augmente de 100 % vos chances de coup critique pour 1 utilisation suivante de Heurt de bouclier. Les coups critiques de Heurt de bouclier augmentent les dégâts de Pourfendre et Blessures profondes de 80 % pendant 8 s."}
MultiLanguageSpellData['fr'][1236421] = {name = "Warrior Mountain Thane 11.2 Class Set 2pc", additional_info = "[q]Explosion de tonnerre a 35 % de chances d’appliquer 5 frappes ionisantes sur les cibles touchées. Chaque frappe inflige ([150% of Attack Power]) point de dégâts de nature."}
MultiLanguageSpellData['fr'][1236422] = {name = "Warrior Mountain Thane 11.2 Class Set 4pc", additional_info = "[q]Les frappes ionisantes infligent 100 % de dégâts supplémentaires. Quand vous déclenchez Frappes ionisantes, vous obtenez une charge d’Explosion de tonnerre et sa prochaine utilisation inflige 100 % de dégâts supplémentaires."}
MultiLanguageSpellData['fr'][1236423] = {name = "Warrior Slayer 11.2 Class Set 2pc", additional_info = "[q]Exécution inflige 10 % de dégâts supplémentaires. Lorsqu’Exécution est appliquée après Mort subite, elle a 10 % de chances par charge d’Accablement sur la cible de déclencher Frappe assassine à 100 % d’efficacité."}
MultiLanguageSpellData['fr'][1236424] = {name = "Warrior Slayer 11.2 Class Set 4pc", additional_info = "[q]Fureur, Protection\n Coup déchaîné inflige 10 % de dégâts supplémentaires et Coup déchaîné a 2 % de chances par charge d’Accablement sur la cible de déclencher Récolte de la tempête à 150 % d’efficacité.\n\nArmes\n Fulgurance inflige 10 % de dégâts supplémentaires et Fulgurance a 2 % de chances par charge d’Accablement sur la cible de déclencher Récolte de la tempête à 150 % d’efficacité.\n(500ms de recharge)"}
