MultiLanguageSpellData['fr'][1236703] = {name = "Trame éternelle", additional_info = "5 s d'incantation\n[q]En atteignant 100 points d’énergie, la Scribe de l’âme initie un rituel pendant 24 s, libérant une série de cônes qui infligent 7273348 point de dégâts des arcanes aux personnages-joueurs touchés.\n\n Les destins touchés infligent Destin blessé au personnage-joueur correspondant."}
