MultiLanguageSpellData['fr'][1236748] = {name = "Paladin Templar 11.2 Class Set 4pc Driver", additional_info = "Instantanée\n[q]Vindicte\n Marteau de la Lumière inflige 0 % de dégâts supplémentaires à la cible principale, touche 0 cibles secondaires supplémentaires et peut désormais être lancé 0 fois supplémentaire après Traînée de cendres.\n\nSacré, Protection\n Marteau de la Lumière inflige 0 % de dégâts supplémentaires à la cible principale, touche 0 cibles secondaires supplémentaires et peut désormais être lancé 0 fois supplémentaire après Œil de Tyr."}
MultiLanguageSpellData['fr'][1236759] = {name = "Explosion de surinfusion", additional_info = "Portée illimitée\nInstantanée\n[q]Rou’ethar inflige 266671 point de dégâts des arcanes à tous les personnages-joueurs toutes les 0.5 s pendant 8 s, tout en absorbant de l’énergie arcanique. Il libère ensuite cette énergie dans une explosion colossale qui inflige 129345416 points de dégâts des arcanes aux personnages-joueurs à moins de 45 m."}
MultiLanguageSpellData['fr'][1236761] = {name = "Dévorer", additional_info = "150 m de portée\nInstantanée\n[q]À 100 points d’énergie, Azhiccar inspire et tente de dévorer tous les personnages-joueurs et créatures de l’arène pendant 18 s, ce qui inflige 606112 point de dégâts d’ombre à tous les personnages-joueurs toutes les 1 s.\n\n Chaque fois qu’Azhiccar réussit à dévorer un personnage-joueur ou une créature vivante, il lance Festin ."}
