MultiLanguageSpellData['fr'][1236792] = {name = "Bombe d’essence", additional_info = "30 m de portée\nInstantanée\n[q]Lorsque vous consommez Explosion d’essence pendant Flamme intérieure, vous lancez une bombe d’essence sur votre cible, [ Dévastation : infligeant ([371% of Spell Power]) point de dégâts des arcanes aux adversaires proches /\n\nPréservation, Augmentation\nrendant ([250% of Spell Power]) point de vie aux personnages alliés proches ] Effet réduit au-delà de 5 cibles."}
