MultiLanguageSpellData['fr'][1236807] = {name = "Faveur de dryade", additional_info = "Instantanée\n[q]Restauration\nLorsque votre dryade disparaît, vos 2 prochaines utilisations de Prompt rétablissement soignent pour 5 % des soins prodigués tant qu’elle était active. 25 % des soins prodigués sont propagés aux personnages alliés proches (effet réduit au - delà de 5 cibles).\n\nÉquilibre, Farouche, Gardien\nLorsque votre dryade disparaît, vos 2 prochaines utilisations d’Éruption stellaire infligent des dégâts pour 2 % des dégâts infligés tant qu’elle était active. 10 % des dégâts infligés sont propagés aux adversaires proches (effet réduit au - delà de 5 cibles)."}
MultiLanguageSpellData['fr'][1236822] = {name = "Afflux de sang", additional_info = "Instantanée\n[q]Impie\nTraitement de douleur inflige 30 % de dégâts supplémentaires et Frappe vampirique augmente les dégâts de votre goule de 20 % pendant 8 s. Cet effet peut être appliqué plusieurs fois simultanément.\n\nSang, Givre\nTraitement de douleur inflige 50 % de dégâts supplémentaires et Frappe vampirique augmente les dégâts de vos armes runiques dansantes de 20 % pendant 8 s. Cet effet peut être appliqué plusieurs fois simultanément."}
MultiLanguageSpellData['fr'][1236824] = {name = "Noyau chargé", additional_info = "300 m de portée\nInstantanée\n[q]Le noyau protège le lanceur ou la lanceuse des dégâts subis. Lorsque le noyau est détruit, il explose en infligeant 34853 point de dégâts cosmiques."}
