MultiLanguageSpellData['fr'][1236989] = {name = "Accumulation de clair de lune", additional_info = "Instantanée\n[q]Équilibre\nÀ l’impact, chaque Éruption stellaire déclenchée par Feu stellaire se propage à un maximum de 3 cibles supplémentaires à 80 % d’efficacité et octroie une charge d’Accumulation de clair de lune. En lançant Fureur d’Élune ou Pleine lune, vous consommez Accumulation de clair de lune et augmentez vos dégâts de 4 % par charge pendant 12 s.\n\nFarouche, Gardien, Restauration\nÀ l’impact, chaque Éruption stellaire déclenchée par Rosser se propage à un maximum de 3 cibles supplémentaires à 20 % d’efficacité et octroie une charge d’Accumulation de clair de lune. En lançant Rayon lunaire, vous consommez Accumulation de clair de lune et augmentez vos dégâts de 4 % par charge pendant 12 s."}
MultiLanguageSpellData['fr'][1236990] = {name = "Suffusion de clair de lune", additional_info = "Instantanée\n[q]Équilibre\nÀ l’impact, chaque Éruption stellaire déclenchée par Feu stellaire se propage à un maximum de 3 cibles supplémentaires à 80 % d’efficacité et octroie une charge d’Accumulation de clair de lune. En lançant Fureur d’Élune ou Pleine lune, vous consommez Accumulation de clair de lune et augmentez vos dégâts de 4 % par charge pendant 12 s.\n\nFarouche, Gardien, Restauration\nÀ l’impact, chaque Éruption stellaire déclenchée par Rosser se propage à un maximum de 3 cibles supplémentaires à 20 % d’efficacité et octroie une charge d’Accumulation de clair de lune. En lançant Rayon lunaire, vous consommez Accumulation de clair de lune et augmentez vos dégâts de 4 % par charge pendant 12 s."}
MultiLanguageSpellData['fr'][1236991] = {name = "Vide dévorant", additional_info = "100 m de portée\nInstantanée\n[q]Lorsque vous subissez des dégâts, vous avez de fortes chances de dévorer l’essence des personnages adverses proches, ce qui inflige 1923  point de dégâts d’ombre répartis entre eux et vous soigne pour 150 % des dégâts.\n\n Les dégâts censés vous tuer n’excédant pas 18656  point vous portent plutôt à 20 % de points de vie et vous transforment en Vide instable pendant 6 s. Si vous dépassez 65 % de points de vie, vous pouvez stabiliser votre état et éviter de mourir. Cet effet ne peut se produire qu’une fois toutes les 8 min. Le nucléus ne peut infliger de dégâts lorsqu’il se recharge."}
