MultiLanguageSpellData['fr'][1236996] = {name = "Âme renforcée", additional_info = "Instantanée\n[q]Sang, Givre, Impie\nExterminer inflige 20 % de dégâts supplémentaires et Marque de la faucheuse peut se cumuler jusqu’à 15 fois supplémentaires. Après l’explosion de Marque de la faucheuse, vos chances de coup critique sont augmentées de 10 % pendant 8 s."}
