MultiLanguageSpellData['fr'][1239486] = {name = "Bordée", additional_info = "100 m de portée\nInstantanée\n[q]Le capitaine Nil’hitan ordonne à son vaisseau amiral de faire un barrage à l’emplacement des personnages-joueurs, infligeant 25 point de dégâts cosmiques. Le barrage dévaste le sol, laissant derrière lui des déchets cosmiques, infligeant 3 point de dégâts cosmiques toutes les 1 s."}
MultiLanguageSpellData['fr'][1239487] = {name = "Javelot de lien", additional_info = "100 m de portée\nInstantanée\n[q]Taah’bat lance des javelots arcaniques sur les personnages-joueurs ciblés, ce qui inflige 2424449 point de dégâts des arcanes aux personnages-joueurs à moins de 8 m des cibles et attache tous les personnages-joueurs touchés.\n\n Chaque lien inflige 606112 points de dégâts des arcanes toutes les 1 s, réduit la vitesse de déplacement de 50 % et augmente en intensité toutes les 5 s, jusqu’à ce que le javelot soit détruit. Cet effet est cumulable."}
