MultiLanguageSpellData['fr'][1245357] = {name = "Griffon aux parures de Norderon", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie cette monture.\n[q]\"Autrefois, les spécialistes du chevauchage de griffon et du chamanisme marteaux-hardis de Norderon paraient souvent leurs griffons d’ornements et d’éléments à plumes, indiquant ainsi leur rang et leur statut.\"\nComptoir"}
MultiLanguageSpellData['fr'][1245358] = {name = "Griffon de Nid-de-l’Aigle du grand chaman", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie cette monture.\n[q]\"Les anciens groupes chamaniques marteaux-hardis qui découvrirent les griffons virent en eux la forme mortelle des élémentaires. Cette rencontre marqua à jamais les générations futures du clan des Marteaux-Hardis.\"\nComptoir"}
MultiLanguageSpellData['fr'][1245359] = {name = "Griffon des hautes-terres au plumage de braise", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie cette monture.\n[q]\"Selon une légende marteau-hardi, le plumage orangé des griffons serait un trait hérité directement de leurs ancêtres élémentaires.\"\nComptoir"}
