MultiLanguageSpellData['fr'][1245361] = {name = "Guide céleste braisaile", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie cette monture.\n[q]\"« Nous suivirent ses ailes de braises étincelantes depuis les contreforts de Khaz Modan… telle une torche indiquant le nord dans un sombre ciel d’été. » – Le Pèlerinage du premier sage-sauvage\"\nComptoir"}
MultiLanguageSpellData['fr'][1245370] = {name = "Trotte-brise hargneux", additional_info = "1.5 s d'incantation\n[q]Invoque et renvoie votre trotte-brise hargneux.\n[q]\"Ce talbuk obstiné est bel et bien dressé. Cavaliers, retenez-vous de le caresser.\"\nComptoir"}
MultiLanguageSpellData['fr'][1245376] = {name = "Chasse-arcane", additional_info = "Instantanée\n[q]Les coups critiques de vos sorts et attaques à distance ont une chance élevée de vous conférer Chasse-arcane jusqu’à 5 fois, ce qui augmente votre score de Coup critique de 14 par cumul pendant 8 s."}
MultiLanguageSpellData['fr'][1245377] = {name = "Déploiement de relocalisateurs", additional_info = "Instantanée\n[q]So’azmi déploie des paires de relocalisateurs pour perturber ses adversaires.\n Lorsqu’un personnage-joueur touche l’un de ces appareils, il est immédiatement téléporté vers l’autre relocalisateur de la paire."}
MultiLanguageSpellData['fr'][1245384] = {name = "Brasier gangrené", additional_info = "Portée illimitée\nInstantanée\n[q]Velaryn embrase l’arène, ce qui inflige 561562 point de dégâts de feu à tous les personnages-joueurs et 140538 supplémentaire toutes les 0.5 s pendant 15 s lorsque chaque pilier du brasier est créé. Cet effet est cumulable.\n\n Les flammes infligent 8435981 points de dégâts de feu toutes les 1 s aux personnages-joueurs qui marchent dans la tempête de feu."}
MultiLanguageSpellData['fr'][1245397] = {name = "Cellule éthérique de la manaforge", additional_info = "Instantanée\n[q]Vos techniques de soins ont une chance d’alimenter la cellule éthérique, ce qui augmentera votre maîtrise de 239 . Ce montant diminuera de ( 239 / 15) par seconde. Dure 15 s s."}
MultiLanguageSpellData['fr'][1245422] = {name = "Tsunami arcanique", additional_info = "Portée illimitée\nInstantanée\n[q]La lieuse d’âmes s’acharne sur sa cible principale, ce qui lui inflige 0  point de dégâts des arcanes toutes les 5.2 s pendant jusqu’à annulation. Le personnage-joueur ciblé par cette frappe voit les dégâts subis de Fouet mystique augmentés de 10  % et les dégâts physiques de 7  % pendant 45 s."}
