MultiLanguageSpellData['fr'][1245431] = {name = "Gazéther symbiotique", additional_info = "Instantanée\n[q]Les blocages, les parades, ou les esquives ont une chance d’éveiller le gazéther, qui se déchaîne et inflige 542  point de dégâts des arcanes répartis entre les adversaires proches, et absorbe 3137  point de dégâts pendant 15 s."}
