MultiLanguageSpellData['fr'][1249462] = {name = "Négociation : cartel Zo", additional_info = "Instantanée\n[q]Vous passez avec le cartel Zo un accord qui vous donne le droit de vous présenter comme membre de ce cartel pendant une semaine.\n\n Contrat de bataillon\n Vous ne pouvez conclure un accord qu’avec un seul cartel chaque semaine. Cet effet est partagé par tous les membres de votre bataillon."}
MultiLanguageSpellData['fr'][1249463] = {name = "[q3]Négociation : cartel Zo", additional_info = "3.5 s d'incantation\nComposants:\nParchemin frais , Instrument manaforgé , Encre chauffée au soleil (25)\nFaction :\nVandales de la manaforge\nRenom :\n8\nRégion :\ncap de l’Ombre\n\n[q3]Négociation : cartel Zo\n[q2]Utilise: Vous passez avec le cartel Zo un accord qui vous donne le droit de vous présenter comme membre de ce cartel pendant une semaine.\n\n Contrat de bataillon\n Vous ne pouvez conclure un accord qu’avec un seul cartel chaque semaine. Cet effet est partagé par tous les membres de votre bataillon.\n70 requis\n[q]\"Un « contrat » à court terme préparé par les personnages-joueurs pratiquant la calligraphie pour promettre l’allégeance d’un bataillon à un cartel de négociants.\""}
MultiLanguageSpellData['fr'][1249464] = {name = "Don d’Élune", additional_info = "Instantanée\n[q]Maîtrise des bêtes, Survie\nDégâts de Bombe de feu de brousse augmentés de 10 %. Lorsque Tempête lunaire se dissipe, vous obtenez Don d’Élune, qui permet à 2 prochaines utilisations de Bombe de feu de brousse d’infliger des dégâts des arcanes et de bénéficier d’un bonus initial de 150 % de dégâts.\n\nPrécision\nDégâts de Tir rapide augmentés de 25 %. Lorsque Tempête lunaire se dissipe, vous obtenez Don d’Élune, qui permet à 2 prochaines utilisations de Visée d’infliger des dégâts des arcanes et de bénéficier d’un bonus de 10 % de dégâts."}
