MultiLanguageSpellData['fr'][1249651] = {name = "Faveur de reshii", additional_info = "Instantanée\n[q]Vous imprégnez vos bandelettes de reshii d’un surplus d’énergie pour les renforcer.\n\n Vous libérez le pouvoir des bandelettes pour qu’elles s’adaptent à votre spécialisation, ce qui vous confère Fauchage éthéré  :\n\nVos sorts et techniques néfastes ont une chance de concentrer les énergies latentes proches pour infliger des dégâts des arcanes répartis entre la cible et les personnages adverses proches. Les personnages adverses dont les points de vie sont inférieurs à 35 % subissent 20 % de dégâts supplémentaires."}
MultiLanguageSpellData['fr'][1249658] = {name = "Souffle de Sindragosa", additional_info = "60 puissance runique\n{Instantanée} {1.5 min de recharge}\n[q]Vous faites appel à l’aide de Sindragosa en combat pendant 8 s, ce qui inflige en continu [([139.788% of Attack Power]) * [(Puissance d'attaque * 0.98)][((Puissance d'attaque + [Offhand Attack Power]) * 2 / 3)] -- 2H, DW / Puissance d'attaque] point de dégâts de givre toutes les 1 s aux adversaires dans un cône devant vous. Le fait de consommer Machine à tuer ou Frimas augmente la durée de 0.8 s. Inflige des dégâts réduits aux cibles secondaires.\n\nConfère une charge de Renforcer l’arme runique au début et 2 runes à la fin de l’effet.\n(100ms de recharge)"}
