MultiLanguageSpellData['fr'][1250314] = {name = "Fleur fantôme", additional_info = "5 m de portée\n2.5 s d'incantation\n[q]Les fleurs fantômes sont les restes énergétiques de la flore originaire de K’aresh, incompatibles avec les recettes algaries.\n\n Vous pouvez les échanger contre des ressources algaries au marché aux ressources. Leur prix varie tous les jours, alors armez-vous de patience pour faire les meilleures affaires !"}
MultiLanguageSpellData['fr'][1250317] = {name = "Fleur fantôme verdoyante", additional_info = "5 m de portée\n2.5 s d'incantation\n[q]Les fleurs fantômes sont les restes énergétiques de la flore originaire de K’aresh, incompatibles avec les recettes algaries.\n\n Vous pouvez les échanger contre des ressources algaries au marché aux ressources. Leur prix varie tous les jours, alors armez-vous de patience pour faire les meilleures affaires !\n\n Certains spécimens de fleurs fantômes ont été observés dans des tailles nettement plus importantes que prévu. Jadis l’une des rares plantes capables de survivre dans les terres arides et impitoyables du désert de K’aresh, elle était réputée pour ses variétés plus imposantes dans les environnements luxuriants des forêts vierges."}
MultiLanguageSpellData['fr'][1250351] = {name = "Gisement dévasté", additional_info = "5 m de portée\n2.5 s d'incantation\n[q]Les spécialistes du minage en quête de fortune sur K’aresh risquent de ne trouver que les maigres ressources d’un monde ravagé. Bien que ce minerai soit inutilisable dans l’artisanat algari, il pourrait présenter un certain intérêt auprès du peuple de Tazavesh."}
MultiLanguageSpellData['fr'][1250356] = {name = "Riche gisement dévasté", additional_info = "5 m de portée\n2.5 s d'incantation\n[q]Les spécialistes du minage en quête de fortune sur K’aresh risquent de ne trouver que les maigres ressources d’un monde ravagé. Bien que ce minerai soit inutilisable dans l’artisanat algari, il pourrait présenter un certain intérêt auprès du peuple de Tazavesh.\n\nDes gisements anormalement grands surgissent parfois du sol, pour le plus grand plaisir des mineurs et mineuses à la recherche d’une source de revenus."}
